/// Minimum production soundness accepted for native terminal certificates.
pub const MIN_TERMINAL_SECURITY_BITS: u16 = 60;

/// Tip5 sponge used by the terminal FRI/MMCS backend.
pub type TerminalTip5Sponge = PaddingFreeSponge<Tip5Perm, 16, 10, 5>;

/// Tip5 2-to-1 compression used by the terminal FRI/MMCS backend.
pub type TerminalTip5Compress = TruncatedPermutation<Tip5Perm, 2, 5, 16>;

/// Goldilocks MMCS for terminal FRI codeword commitments.
pub type TerminalFriValMmcs = MerkleTreeMmcs<
    <Goldilocks as Field>::Packing,
    <Goldilocks as Field>::Packing,
    TerminalTip5Sponge,
    TerminalTip5Compress,
    2,
    5,
>;

/// Extension field used for terminal FRI challenges.
pub type TerminalFriChallenge = BinomialExtensionField<Goldilocks, 2>;

/// Extension-MMCS for terminal FRI commit-phase codewords.
pub type TerminalFriChallengeMmcs =
    ExtensionMmcs<Goldilocks, TerminalFriChallenge, TerminalFriValMmcs>;

/// Fiat-Shamir challenger for terminal FRI, over recursive 5-round Tip5.
pub type TerminalFriChallenger = DuplexChallenger<Goldilocks, Tip5Perm, 16, 10>;

/// DFT implementation used by terminal FRI.
pub type TerminalFriDft = Radix2DitParallel<Goldilocks>;

/// Native terminal FRI PCS over Goldilocks with 5-round Tip5 commitments.
pub type TerminalFriPcs =
    TwoAdicFriPcs<Goldilocks, TerminalFriDft, TerminalFriValMmcs, TerminalFriChallengeMmcs>;

/// Terminal FRI commitment type for Goldilocks codewords.
pub type TerminalFriCommitment =
    <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Commitment;

/// Terminal FRI proof type for Goldilocks codewords.
pub type TerminalFriProof =
    <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Proof;

type TerminalFriDomain =
    <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain;
type TerminalFriProverData =
    <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::ProverData;

struct TerminalNpoTip5LookupAirFoldConstants {
    mds: [[TerminalFriChallenge; 16]; 16],
    round_constants: [[TerminalFriChallenge; 16]; TIP5_PERM_ROUNDS],
    pow8: [TerminalFriChallenge; 8],
    two32_minus_one: TerminalFriChallenge,
}

/// Concrete terminal input-opening proof type used by [`TerminalFriProof`].
pub type TerminalFriInputProof = Vec<BatchOpening<Goldilocks, TerminalFriValMmcs>>;

#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalPackedMerkleDigest {
    pub lo: [u8; 20],
    pub hi: [u8; 20],
}

impl TerminalPackedMerkleDigest {
    fn from_goldilocks_digest(digest: &[Goldilocks; 5]) -> Self {
        let mut packed = [0u8; 40];
        for (limb, value) in digest.iter().enumerate() {
            let start = limb * 8;
            packed[start..start + 8]
                .copy_from_slice(&PrimeField64::as_canonical_u64(value).to_le_bytes());
        }
        let mut lo = [0u8; 20];
        let mut hi = [0u8; 20];
        lo.copy_from_slice(&packed[..20]);
        hi.copy_from_slice(&packed[20..]);
        Self { lo, hi }
    }

    fn to_goldilocks_digest(self) -> Option<[Goldilocks; 5]> {
        let mut packed = [0u8; 40];
        packed[..20].copy_from_slice(&self.lo);
        packed[20..].copy_from_slice(&self.hi);
        let mut digest = [Goldilocks::ZERO; 5];
        for limb in 0..digest.len() {
            let start = limb * 8;
            let mut bytes = [0u8; 8];
            bytes.copy_from_slice(&packed[start..start + 8]);
            let value = u64::from_le_bytes(bytes);
            if value >= Goldilocks::ORDER_U64 {
                return None;
            }
            digest[limb] = Goldilocks::from_u64(value);
        }
        Some(digest)
    }
}

/// A binary Merkle authentication path pruned against the previous sorted path.
#[derive(Clone, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalPrunedMerklePath {
    pub leaf_index: usize,
    pub siblings: Vec<TerminalPackedMerkleDigest>,
}

/// Compact representation of same-tree binary Merkle paths for all terminal
/// FRI queries. Query indices are deliberately not serialized; the verifier
/// must rederive them from the Fiat-Shamir transcript and pass them to
/// decompression.
#[derive(Clone, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalPrunedMerklePaths {
    pub original_order: Vec<u32>,
    pub paths: Vec<TerminalPrunedMerklePath>,
}

/// Compact query openings for one terminal FRI input commitment batch.
#[derive(Clone, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalCompressedFriInputBatch {
    /// Leaf payloads in the same sorted-unique order as
    /// `pruned_opening_proof.paths`. `original_order` reconstructs the
    /// per-query vector expected by Plonky3's verifier.
    pub opened_values: Vec<Vec<Vec<Goldilocks>>>,
    pub pruned_opening_proof: TerminalPrunedMerklePaths,
}

/// Compact query openings for one terminal FRI commit-phase round.
#[derive(Clone, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalCompressedFriCommitRound {
    pub log_arity: u8,
    /// Reduced-coset sibling payloads in original query order. Two queries can
    /// share a reduced Merkle leaf while omitting different coset positions, so
    /// these are intentionally independent from the pruned Merkle path
    /// dictionary.
    pub sibling_values: Vec<Vec<TerminalFriChallenge>>,
    pub pruned_opening_proof: TerminalPrunedMerklePaths,
}

/// Lossless, terminal-only compressed form of [`TerminalFriProof`].
///
/// This is modeled on Plonky2's terminal FRI proof compression, but is written
/// directly against the in-tree Plonky3 proof shape. It keeps the FRI algebra
/// unchanged and only compresses duplicated Merkle authentication material
/// across transcript-derived queries.
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct TerminalCompressedFriProof {
    pub commit_phase_commits: Vec<TerminalFriCommitment>,
    pub commit_pow_witnesses: Vec<Goldilocks>,
    pub input_batches: Vec<TerminalCompressedFriInputBatch>,
    pub commit_rounds: Vec<TerminalCompressedFriCommitRound>,
    pub final_poly: Vec<TerminalFriChallenge>,
    pub query_pow_witness: Goldilocks,
}

/// Stable fingerprint for a compiled terminal verifier circuit.
///
/// This intentionally records only structural fields that affect the witness
/// interface and operation sequence.  Backend-specific proving keys may bind
/// more data, but a mismatch here is always a cache miss.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalCircuitFingerprint {
    pub witness_count: u32,
    pub public_flat_len: usize,
    pub private_flat_len: usize,
    pub ops_len: usize,
}

impl TerminalCircuitFingerprint {
    pub const fn from_circuit<F>(circuit: &Circuit<F>) -> Self {
        Self {
            witness_count: circuit.witness_count,
            public_flat_len: circuit.public_flat_len,
            private_flat_len: circuit.private_flat_len,
            ops_len: circuit.ops.len(),
        }
    }
}

/// Executed verifier-circuit witness handed to a terminal compressor.
///
/// `public_inputs` are the verifier-visible statement values for the terminal
/// proof. `private_inputs` and `traces` are prover-only data used to witness
/// circuit execution. The final compact certificate must bind the public inputs
/// and the terminal circuit fingerprint/proving key.
pub struct TerminalWitness<F> {
    pub fingerprint: TerminalCircuitFingerprint,
    pub public_inputs: Vec<F>,
    pub private_inputs: Vec<F>,
    pub traces: Traces<F>,
}

/// Contract for a native compact terminal compressor.
///
/// This is deliberately independent of the current batch-STARK certificate
/// type. Implementations compile a `p3_circuit` verifier circuit into their own
/// proving/verifying keys, then prove an executed [`TerminalWitness`].
pub trait TerminalCompressor<F: Field> {
    type ProvingKey;
    type VerifyingKey;
    type Proof;
    type Error;

    /// Protocol identifier committed by wire/certificate metadata.
    fn protocol_id(&self) -> &'static str;

    /// Compile a verifier circuit into terminal-compressor keys.
    fn compile(
        &self,
        circuit: &Circuit<F>,
    ) -> Result<(Self::ProvingKey, Self::VerifyingKey), Self::Error>;

    /// Prove one executed verifier circuit.
    fn prove(
        &self,
        proving_key: &Self::ProvingKey,
        witness: &TerminalWitness<F>,
    ) -> Result<Self::Proof, Self::Error>;

    /// Verify a terminal proof against public inputs and a circuit fingerprint.
    fn verify(
        &self,
        verifying_key: &Self::VerifyingKey,
        proof: &Self::Proof,
        fingerprint: TerminalCircuitFingerprint,
        public_inputs: &[F],
    ) -> Result<(), Self::Error>;

    /// Serialize a proof into the certificate body.
    fn serialize_proof(&self, proof: &Self::Proof) -> Result<Vec<u8>, Self::Error>;
}

/// Minimal metadata all native terminal certificates must expose.
#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalCertificateHeader {
    pub version: u32,
    pub protocol_id: String,
    pub security_bits: u16,
    pub fingerprint: TerminalCircuitFingerprint,
    pub relation_digest: Option<TerminalRelationDigest>,
}

/// Terminal proof body semantics bound by the certificate digest.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub enum TerminalProofKind {
    /// Local sampled/folded checkpoint used for development measurements.
    ///
    /// This kind is intentionally not the production terminal compressor: it
    /// verifies the implemented local proof components, but does not by itself
    /// establish a complete polynomial IOP/proximity argument for the terminal
    /// relation.
    #[cfg(test)]
    LocalCheckpoint,
    /// Production terminal proof backend.
    Production,
}

