pub struct TerminalNpoPolynomialRecomposeResidualQuotientProof {
    pub selected_profile: TerminalNpoPolynomialFriProfile,
    pub quotient_profile: TerminalNpoPolynomialFriProfile,
    pub selected_commitment: TerminalFriCommitment,
    pub quotient_commitment: TerminalFriCommitment,
    pub opened_selected_basis: Vec<Vec<u64>>,
    pub opened_quotient_basis: Vec<Vec<u64>>,
    pub proof: TerminalCompressedFriProof,
}

/// Combined FRI-native NPO checkpoint for residual-zero and recompose rows.
///
/// This avoids paying two independent selected-column FRI openings while the
/// final backend is still being assembled: the selected prover-dependent
/// column root fixes both folding challenges, then the prover commits the
/// residual-zero composition and recompose residual-relation quotient and opens
/// all three codewords at one transcript-derived point with one FRI proof.
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct TerminalNpoPolynomialFriResidualZeroRecomposeProof {
    pub selected_profile: TerminalNpoPolynomialFriProfile,
    pub composition_profile: TerminalCompactCompositionFriProfile,
    pub quotient_profile: TerminalNpoPolynomialFriProfile,
    pub selected_commitment: TerminalFriCommitment,
    pub composition_commitment: TerminalFriCommitment,
    pub quotient_commitment: TerminalFriCommitment,
    pub opened_selected_basis: Vec<Vec<u64>>,
    pub opened_composition_basis: Vec<Vec<u64>>,
    pub opened_quotient_basis: Vec<Vec<u64>>,
    pub proof: TerminalCompressedFriProof,
}

/// Combined FRI-native NPO checkpoint for residual-zero, recompose rows, and
/// the Tip5 lookup-IO-to-NPO-value bridge on the NPO row domain.
///
/// This extends `TerminalNpoPolynomialFriResidualZeroRecomposeProof` by using
/// the same opened prover-dependent NPO table for the value-bridge relation,
/// instead of committing the witness-value columns as a second FRI table.
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct TerminalNpoPolynomialFriResidualZeroRecomposeValueBridgeProof {
    pub selected_profile: TerminalNpoPolynomialFriProfile,
    pub value_profile: TerminalNpoPolynomialFriProfile,
    pub lookup_io_profile: TerminalNpoTip5LookupNpoRowsIoProfile,
    pub composition_profile: TerminalCompactCompositionFriProfile,
    pub recompose_quotient_profile: TerminalNpoPolynomialFriProfile,
    pub padding_quotient_profile: TerminalNpoPolynomialFriProfile,
    pub value_bridge_quotient_profile: TerminalNpoTip5LookupNpoRowsValueBridgeQuotientProfile,
    pub selected_lookup_commitment: TerminalFriCommitment,
    pub composition_commitment: TerminalFriCommitment,
    pub recompose_quotient_commitment: TerminalFriCommitment,
    pub padding_value_bridge_quotient_commitment: TerminalFriCommitment,
    pub opened_selected_basis: Vec<Vec<u64>>,
    pub opened_lookup_io_basis: Vec<Vec<u64>>,
    pub opened_composition_basis: Vec<Vec<u64>>,
    pub opened_recompose_quotient_basis: Vec<Vec<u64>>,
    pub opened_padding_quotient_basis: Vec<Vec<u64>>,
    pub opened_value_bridge_quotient_basis: Vec<Vec<u64>>,
    pub proof: TerminalCompressedFriProof,
}

/// One flattened component in the production-equivalent supported-NPO residual
/// domain.
#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct TerminalNpoResidualComponentRef {
    pub npo_index: usize,
    pub component_offset: usize,
    pub kind: TerminalNpoResidualKind,
    pub limb: usize,
    pub basis_component: usize,
}

impl<F: Field> TerminalLinearExpression<F> {
    pub fn zero() -> Self {
        Self { terms: Vec::new() }
    }

    pub fn one() -> Self {
        Self {
            terms: vec![TerminalLinearTerm {
                coeff: F::ONE,
                variable: TerminalLinearVariable::One,
            }],
        }
    }

    pub fn witness(witness_id: WitnessId) -> Self {
        Self {
            terms: vec![TerminalLinearTerm {
                coeff: F::ONE,
                variable: TerminalLinearVariable::Witness(witness_id),
            }],
        }
    }

    pub fn public(public_pos: usize) -> Self {
        Self {
            terms: vec![TerminalLinearTerm {
                coeff: F::ONE,
                variable: TerminalLinearVariable::Public(public_pos),
            }],
        }
    }

    pub fn constant(value: F) -> Self {
        Self {
            terms: vec![TerminalLinearTerm {
                coeff: value,
                variable: TerminalLinearVariable::One,
            }],
        }
    }

    pub fn scaled(mut self, coeff: F) -> Self {
        for term in &mut self.terms {
            term.coeff *= coeff;
        }
        self
    }

    pub fn plus(mut self, rhs: Self) -> Self {
        self.terms.extend(rhs.terms);
        self
    }

    pub fn minus(self, rhs: Self) -> Self {
        self.plus(rhs.scaled(-F::ONE))
    }

    fn variable_sort_key(variable: TerminalLinearVariable) -> (u8, usize) {
        match variable {
            TerminalLinearVariable::One => (0, 0),
            TerminalLinearVariable::Public(public_pos) => (1, public_pos),
            TerminalLinearVariable::Witness(witness_id) => (2, witness_id.0 as usize),
        }
    }

    fn canonicalize(mut self) -> Self {
        self.terms.sort_by_key(|term| Self::variable_sort_key(term.variable));
        let mut canonical = Vec::<TerminalLinearTerm<F>>::with_capacity(self.terms.len());
        for term in self.terms {
            if term.coeff == F::ZERO {
                continue;
            }
            if let Some(last) = canonical.last_mut() {
                if last.variable == term.variable {
                    last.coeff += term.coeff;
                    if last.coeff == F::ZERO {
                        canonical.pop();
                    }
                    continue;
                }
            }
            canonical.push(term);
        }
        Self { terms: canonical }
    }

    fn evaluate(
        &self,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
    ) -> Result<F, NativeTerminalVerifyError> {
        let mut acc = F::ZERO;
        for term in &self.terms {
            let value = match term.variable {
                TerminalLinearVariable::One => F::ONE,
                TerminalLinearVariable::Public(public_pos) => public_inputs
                    .get(public_pos)
                    .copied()
                    .ok_or(NativeTerminalVerifyError::PublicInputLengthMismatch {
                        expected: public_pos + 1,
                        got: public_inputs.len(),
                    })?,
                TerminalLinearVariable::Witness(witness_id) => witness
                    .traces
                    .witness_trace
                    .get_value(witness_id)
                    .copied()
                    .ok_or(NativeTerminalVerifyError::MissingWitness {
                        witness_id: witness_id.0,
                    })?,
            };
            acc += term.coeff * value;
        }
        Ok(acc)
    }
}

impl<F: Field> TerminalQuadraticRelation<F> {
    pub fn residuals(
        &self,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
    ) -> Result<Vec<F>, NativeTerminalVerifyError> {
        let mut residuals = Vec::with_capacity(self.constraints.len());
        for constraint in &self.constraints {
            let a = constraint.a.evaluate(public_inputs, witness)?;
            let b = constraint.b.evaluate(public_inputs, witness)?;
            let c = constraint.c.evaluate(public_inputs, witness)?;
            residuals.push(a * b - c);
        }
        Ok(residuals)
    }

    pub fn verify(
        &self,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
    ) -> Result<(), NativeTerminalVerifyError> {
        for (quadratic_index, (constraint, residual)) in self
            .constraints
            .iter()
            .zip(self.residuals(public_inputs, witness)?)
            .enumerate()
        {
            if residual != F::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalQuadraticConstraintViolation {
                        quadratic_index,
                        source_constraint_index: constraint.source_constraint_index,
                        kind: constraint.kind,
                    },
                );
            }
        }
        Ok(())
    }
}

