    fn prove_terminal_npo_tip5_packed_lookup_air_logup_selected_trace_bridge_from_prepared_goldilocks<
        F,
    >(
        prelude: &TerminalProofPrelude,
        columns: &TerminalNpoPolynomialColumns<F>,
        selected_lookup: &TerminalNpoSelectedLookupProverData,
        packed_trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        packed_trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<
        TerminalNpoTip5PackedLookupAirLogupSelectedTraceBridgeProof,
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(
            packed_trace_profile,
            packed_trace,
        )?;
        let selected_profile = selected_lookup.selected_profile.clone();
        let lookup_io_profile = selected_lookup.lookup_io_profile.clone();
        let selected_lookup_matrix = &selected_lookup.selected_lookup_matrix;
        let air_quotient_profile =
            Self::terminal_npo_tip5_packed_lookup_air_algebra_quotient_profile(
                packed_trace_profile,
            )?;
        let logup_table_profile =
            Self::terminal_npo_tip5_packed_lookup_logup_table_profile(packed_trace_profile)?;
        let logup_accumulator_profile =
            Self::terminal_npo_tip5_packed_lookup_logup_accumulator_profile(packed_trace_profile)?;
        let logup_quotient_profile =
            Self::terminal_npo_tip5_packed_lookup_logup_quotient_profile(packed_trace_profile)?;
        let selected_bridge_accumulator_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_accumulator_profile(
                selected_profile.rows,
                selected_profile.padded_rows,
                selected_profile.proximity,
            )?;
        let packed_bridge_accumulator_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_accumulator_profile(
                packed_trace_profile.rows,
                packed_trace_profile.padded_rows,
                packed_trace_profile.proximity,
            )?;
        let selected_bridge_quotient_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_quotient_profile(
                selected_profile.rows,
                selected_profile.padded_rows,
                selected_profile.proximity,
            )?;
        let packed_bridge_quotient_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_quotient_profile(
                packed_trace_profile.rows,
                packed_trace_profile.padded_rows,
                packed_trace_profile.proximity,
            )?;
        for profile in [
            selected_profile.proximity,
            lookup_io_profile.proximity,
            packed_trace_profile.proximity,
            air_quotient_profile.proximity,
            logup_table_profile.proximity,
            logup_accumulator_profile.proximity,
            logup_quotient_profile.proximity,
            selected_bridge_accumulator_profile.proximity,
            packed_bridge_accumulator_profile.proximity,
            selected_bridge_quotient_profile.proximity,
            packed_bridge_quotient_profile.proximity,
        ] {
            if profile != prelude.relation_profile.proximity {
                return Err(
                    NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                        expected: prelude.relation_profile.proximity.proof_parameters(),
                        got: profile.proof_parameters(),
                    },
                );
            }
        }

        let table_matrix =
            Self::terminal_npo_tip5_packed_lookup_logup_table_multiplicity_matrix_goldilocks(
                packed_trace_profile,
                packed_trace,
            )?;
        Self::validate_terminal_npo_tip5_packed_lookup_logup_table_matrix(
            &logup_table_profile,
            &table_matrix,
        )?;
        let (packed_npo_io_profile, packed_npo_io_matrix) =
            Self::terminal_npo_tip5_packed_lookup_npo_io_matrix_goldilocks(
                packed_trace_profile,
                packed_trace,
            )?;
        let (selected_lane_selector_evals, selected_rank_evals) =
            Self::terminal_npo_tip5_lookup_selected_npo_io_lane_selector_rank_evals(columns)?;
        let (packed_lane_selector_evals, packed_rank_evals) =
            Self::terminal_npo_tip5_packed_lookup_npo_io_lane_selector_rank_evals(
                columns,
                packed_trace_profile,
            )?;

        let (pcs, mut challenger) =
            Self::terminal_fri_pcs_and_challenger(packed_trace_profile.proximity)?;
        let selected_domain = <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::natural_domain_for_degree(
            &pcs, selected_profile.padded_rows
        );
        let packed_domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                packed_trace_profile.padded_rows,
            );
        let selected_lookup_commitment = selected_lookup.selected_lookup_commitment.clone();
        let selected_lookup_data = &selected_lookup.selected_lookup_data;
        let selected_lookup_commitment_digest = selected_lookup.commitment_digest;
        let (packed_trace_table_commitment, packed_trace_table_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [
                    (packed_domain, packed_trace.clone()),
                    (packed_domain, table_matrix.clone()),
                ],
            );
        let packed_trace_table_commitment_digest =
            Self::terminal_fri_commitment_digest(&packed_trace_table_commitment)?;
        Self::verify_terminal_fri_prelude_commitments(
            prelude,
            &[
                selected_lookup_commitment_digest,
                packed_trace_table_commitment_digest,
            ],
        )?;

        Self::seed_terminal_npo_tip5_packed_lookup_air_logup_selected_trace_bridge_challenger(
            &mut challenger,
            prelude,
            &selected_profile,
            &lookup_io_profile,
            packed_trace_profile,
            &air_quotient_profile,
            &logup_table_profile,
            &logup_accumulator_profile,
            &logup_quotient_profile,
            &selected_bridge_accumulator_profile,
            &packed_bridge_accumulator_profile,
            &selected_bridge_quotient_profile,
            &packed_bridge_quotient_profile,
        );
        challenger.observe(selected_lookup_commitment.clone());
        challenger.observe(packed_trace_table_commitment.clone());
        let air_alpha: TerminalFriChallenge = challenger.sample_algebra_element();
        let logup_alpha: TerminalFriChallenge = challenger.sample_algebra_element();
        let logup_beta: TerminalFriChallenge = challenger.sample_algebra_element();
        let bridge_alpha: TerminalFriChallenge = challenger.sample_algebra_element();
        let bridge_beta_rank: TerminalFriChallenge = challenger.sample_algebra_element();
        let bridge_beta_limb: TerminalFriChallenge = challenger.sample_algebra_element();

        let air_quotient_domain =
            packed_domain.create_disjoint_domain(air_quotient_profile.padded_rows);
        let air_quotient_matrix =
            Self::terminal_npo_tip5_packed_lookup_air_algebra_quotient_matrix_goldilocks(
                packed_domain,
                air_quotient_domain,
                packed_trace_profile,
                packed_trace,
                air_alpha,
            )?;

        let logup_challenges =
            vec![(logup_alpha, logup_beta); Self::terminal_npo_tip5_packed_lookup_logup_interactions()];
        let (logup_accumulator_matrix, logup_final_cumulatives) =
            Self::terminal_npo_tip5_packed_lookup_logup_accumulator_matrix_goldilocks(
                packed_trace_profile,
                packed_trace,
                &table_matrix,
                &logup_challenges,
            )?;

        let (selected_bridge_accumulator_matrix, selected_bridge_final_cumulatives) =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_accumulator_matrix_goldilocks(
                selected_lookup_matrix,
                selected_profile.basis_columns,
                selected_profile.rows,
                selected_profile.padded_rows,
                &selected_lane_selector_evals,
                &selected_rank_evals,
                TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
            )?;
        let (packed_bridge_accumulator_matrix, packed_bridge_final_cumulatives) =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_accumulator_matrix_goldilocks(
                &packed_npo_io_matrix,
                0,
                packed_npo_io_profile.rows,
                packed_npo_io_profile.padded_rows,
                &packed_lane_selector_evals,
                &packed_rank_evals,
                -TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
            )?;
        for (selected, packed) in selected_bridge_final_cumulatives
            .iter()
            .zip(packed_bridge_final_cumulatives.iter())
        {
            if *selected + *packed != TerminalFriChallenge::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                        label: "tip5_packed_air_logup_selected_trace_bridge_final".into(),
                    },
                );
            }
        }
        let (accumulator_commitment, accumulator_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [
                    (packed_domain, logup_accumulator_matrix.clone()),
                    (selected_domain, selected_bridge_accumulator_matrix.clone()),
                    (packed_domain, packed_bridge_accumulator_matrix.clone()),
                ],
            );
        challenger.observe(accumulator_commitment.clone());
        challenger.observe_algebra_slice(&logup_final_cumulatives);
        challenger.observe_algebra_slice(&selected_bridge_final_cumulatives);
        challenger.observe_algebra_slice(&packed_bridge_final_cumulatives);
        let logup_gamma: TerminalFriChallenge = challenger.sample_algebra_element();
        let bridge_gamma: TerminalFriChallenge = challenger.sample_algebra_element();

        let logup_quotient_domain =
            packed_domain.create_disjoint_domain(logup_quotient_profile.padded_rows);
        let logup_quotient_matrix =
            Self::terminal_npo_tip5_packed_lookup_logup_quotient_matrix_goldilocks(
                packed_domain,
                logup_quotient_domain,
                packed_trace_profile,
                packed_trace,
                &logup_table_profile,
                &table_matrix,
                &logup_accumulator_matrix,
                &logup_final_cumulatives,
                &logup_challenges,
                logup_gamma,
            )?;
        let selected_bridge_quotient_domain =
            selected_domain.create_disjoint_domain(selected_bridge_quotient_profile.padded_rows);
        let packed_bridge_quotient_domain =
            packed_domain.create_disjoint_domain(packed_bridge_quotient_profile.padded_rows);
        let selected_bridge_quotient_matrix =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_quotient_matrix_goldilocks(
                selected_domain,
                selected_bridge_quotient_domain,
                selected_lookup_matrix,
                &selected_bridge_accumulator_matrix,
                &selected_bridge_final_cumulatives,
                &selected_lane_selector_evals,
                &selected_rank_evals,
                selected_profile.basis_columns,
                selected_profile.rows,
                selected_profile.padded_rows,
                TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
                bridge_gamma,
            )?;
        let packed_bridge_quotient_matrix =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_quotient_matrix_goldilocks(
                packed_domain,
                packed_bridge_quotient_domain,
                &packed_npo_io_matrix,
                &packed_bridge_accumulator_matrix,
                &packed_bridge_final_cumulatives,
                &packed_lane_selector_evals,
                &packed_rank_evals,
                0,
                packed_npo_io_profile.rows,
                packed_npo_io_profile.padded_rows,
                -TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
                bridge_gamma,
            )?;
        let (quotient_commitment, quotient_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [
                    (air_quotient_domain, air_quotient_matrix),
                    (logup_quotient_domain, logup_quotient_matrix),
                    (
                        selected_bridge_quotient_domain,
                        selected_bridge_quotient_matrix,
                    ),
                    (packed_bridge_quotient_domain, packed_bridge_quotient_matrix),
                ],
            );
        challenger.observe(quotient_commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let packed_next_zeta = packed_domain.next_point(zeta).ok_or_else(|| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason:
                    "terminal packed AIR+LogUp selected-trace bridge packed domain has no successor"
                        .into(),
            }
        })?;
        let selected_next_zeta = selected_domain.next_point(zeta).ok_or_else(|| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason:
                    "terminal packed AIR+LogUp selected-trace bridge selected domain has no successor"
                        .into(),
            }
        })?;

        let (opened_values, plain_proof) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::open(
                &pcs,
                vec![
                    (selected_lookup_data, vec![vec![zeta]]),
                    (
                        &packed_trace_table_data,
                        vec![vec![zeta], vec![zeta]],
                    ),
                    (
                        &accumulator_data,
                        vec![
                            vec![zeta, packed_next_zeta],
                            vec![zeta, selected_next_zeta],
                            vec![zeta, packed_next_zeta],
                        ],
                    ),
                    (
                        &quotient_data,
                        vec![vec![zeta], vec![zeta], vec![zeta], vec![zeta]],
                    ),
                ],
                &mut challenger,
            );
        let opened_selected_lookup_basis =
            Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 0)?;
        let opened_packed_trace_basis =
            Self::terminal_npo_opened_commitment_matrix_basis_u64(&opened_values, 1, 0)?;
        let opened_logup_table_basis =
            Self::terminal_npo_opened_commitment_matrix_basis_u64(&opened_values, 1, 1)?;
        let opened_logup_accumulator_points_basis =
            Self::terminal_npo_opened_commitment_matrix_points_basis_u64(&opened_values, 2, 0)?;
        let opened_selected_bridge_accumulator_points_basis =
            Self::terminal_npo_opened_commitment_matrix_points_basis_u64(&opened_values, 2, 1)?;
        let opened_packed_bridge_accumulator_points_basis =
            Self::terminal_npo_opened_commitment_matrix_points_basis_u64(&opened_values, 2, 2)?;
        let opened_air_quotient_basis =
            Self::terminal_npo_opened_commitment_matrix_basis_u64(&opened_values, 3, 0)?;
        let opened_logup_quotient_basis =
            Self::terminal_npo_opened_commitment_matrix_basis_u64(&opened_values, 3, 1)?;
        let opened_selected_bridge_quotient_basis =
            Self::terminal_npo_opened_commitment_matrix_basis_u64(&opened_values, 3, 2)?;
        let opened_packed_bridge_quotient_basis =
            Self::terminal_npo_opened_commitment_matrix_basis_u64(&opened_values, 3, 3)?;

        let mut query_challenger = TerminalFriChallenger::new(Tip5Perm);
        Self::seed_terminal_npo_tip5_packed_lookup_air_logup_selected_trace_bridge_challenger(
            &mut query_challenger,
            prelude,
            &selected_profile,
            &lookup_io_profile,
            packed_trace_profile,
            &air_quotient_profile,
            &logup_table_profile,
            &logup_accumulator_profile,
            &logup_quotient_profile,
            &selected_bridge_accumulator_profile,
            &packed_bridge_accumulator_profile,
            &selected_bridge_quotient_profile,
            &packed_bridge_quotient_profile,
        );
        query_challenger.observe(selected_lookup_commitment.clone());
        query_challenger.observe(packed_trace_table_commitment.clone());
        for _ in 0..6 {
            let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        }
        query_challenger.observe(accumulator_commitment.clone());
        query_challenger.observe_algebra_slice(&logup_final_cumulatives);
        query_challenger.observe_algebra_slice(&selected_bridge_final_cumulatives);
        query_challenger.observe_algebra_slice(&packed_bridge_final_cumulatives);
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe(quotient_commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        for matrix in &opened_values {
            for round in matrix {
                for point_values in round {
                    query_challenger.observe_algebra_slice(point_values);
                }
            }
        }
        let query_indices = Self::derive_terminal_fri_query_indices_from_challenger(
            &mut query_challenger,
            &plain_proof,
            packed_trace_profile.proximity,
        )?;
        let proof = Self::compress_terminal_fri_proof(&plain_proof, &query_indices)?;

        Ok(
            TerminalNpoTip5PackedLookupAirLogupSelectedTraceBridgeProof {
                selected_profile,
                lookup_io_profile,
                packed_trace_profile: packed_trace_profile.clone(),
                air_quotient_profile,
                logup_table_profile,
                logup_accumulator_profile,
                logup_quotient_profile,
                selected_bridge_accumulator_profile,
                packed_bridge_accumulator_profile,
                selected_bridge_quotient_profile,
                packed_bridge_quotient_profile,
                selected_lookup_commitment,
                packed_trace_table_commitment,
                accumulator_commitment,
                quotient_commitment,
                logup_final_cumulative_basis: logup_final_cumulatives
                    .iter()
                    .map(Self::goldilocks_basis_u64)
                    .collect(),
                selected_bridge_final_cumulative_basis: selected_bridge_final_cumulatives
                    .iter()
                    .map(Self::goldilocks_basis_u64)
                    .collect(),
                packed_bridge_final_cumulative_basis: packed_bridge_final_cumulatives
                    .iter()
                    .map(Self::goldilocks_basis_u64)
                    .collect(),
                opened_selected_lookup_basis,
                opened_packed_trace_basis,
                opened_air_quotient_basis,
                opened_logup_table_basis,
                opened_logup_accumulator_points_basis,
                opened_logup_quotient_basis,
                opened_selected_bridge_accumulator_points_basis,
                opened_packed_bridge_accumulator_points_basis,
                opened_selected_bridge_quotient_basis,
                opened_packed_bridge_quotient_basis,
                proof,
            },
        )
    }

    pub fn prove_terminal_npo_tip5_packed_lookup_npo_io_projection_selected_bridge_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
        prelude: &TerminalProofPrelude,
    ) -> Result<
        TerminalNpoTip5PackedLookupNpoIoProjectionSelectedBridgeProof,
        NativeTerminalVerifyError,
    >
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        self.verify_proof_prelude_goldilocks(verifying_key, public_inputs, prelude)?;
        let columns = self.terminal_npo_polynomial_columns_goldilocks(verifying_key, witness)?;
        let trace_profile = Self::terminal_npo_tip5_lookup_trace_profile(verifying_key);
        let selected_lookup =
            Self::prepare_terminal_npo_selected_lookup_prover_data_from_values_goldilocks(
                &trace_profile,
                &columns,
            )?;
        let (_, packed_trace_profile, packed_trace) =
            self.terminal_npo_tip5_packed_lookup_trace_goldilocks(verifying_key, witness)?;
        Self::prove_terminal_npo_tip5_packed_lookup_npo_io_projection_selected_bridge_from_prepared_goldilocks(
            prelude,
            &columns,
            &selected_lookup,
            &packed_trace_profile,
            &packed_trace,
        )
    }

    fn prove_terminal_npo_tip5_packed_lookup_npo_io_projection_selected_bridge_from_prepared_goldilocks<
        F,
    >(
        prelude: &TerminalProofPrelude,
        columns: &TerminalNpoPolynomialColumns<F>,
        selected_lookup: &TerminalNpoSelectedLookupProverData,
        packed_trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        packed_trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<
        TerminalNpoTip5PackedLookupNpoIoProjectionSelectedBridgeProof,
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(
            packed_trace_profile,
            packed_trace,
        )?;
        let selected_profile = selected_lookup.selected_profile.clone();
        let lookup_io_profile = selected_lookup.lookup_io_profile.clone();
        let selected_lookup_matrix = &selected_lookup.selected_lookup_matrix;
        let (packed_npo_io_profile, packed_npo_io_matrix) =
            Self::terminal_npo_tip5_packed_lookup_npo_io_matrix_goldilocks(
                packed_trace_profile,
                packed_trace,
            )?;
        let projection_quotient_profile =
            Self::terminal_npo_tip5_packed_lookup_npo_io_projection_quotient_profile(
                packed_trace_profile,
            )?;
        let selected_accumulator_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_accumulator_profile(
                selected_profile.rows,
                selected_profile.padded_rows,
                selected_profile.proximity,
            )?;
        let packed_accumulator_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_accumulator_profile(
                packed_npo_io_profile.rows,
                packed_npo_io_profile.padded_rows,
                packed_npo_io_profile.proximity,
            )?;
        let selected_bridge_quotient_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_quotient_profile(
                selected_profile.rows,
                selected_profile.padded_rows,
                selected_profile.proximity,
            )?;
        let packed_bridge_quotient_profile =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_quotient_profile(
                packed_npo_io_profile.rows,
                packed_npo_io_profile.padded_rows,
                packed_npo_io_profile.proximity,
            )?;
        for profile in [
            selected_profile.proximity,
            lookup_io_profile.proximity,
            packed_trace_profile.proximity,
            packed_npo_io_profile.proximity,
            projection_quotient_profile.proximity,
            selected_accumulator_profile.proximity,
            packed_accumulator_profile.proximity,
            selected_bridge_quotient_profile.proximity,
            packed_bridge_quotient_profile.proximity,
        ] {
            if profile != prelude.relation_profile.proximity {
                return Err(
                    NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                        expected: prelude.relation_profile.proximity.proof_parameters(),
                        got: profile.proof_parameters(),
                    },
                );
            }
        }

        let (selected_lane_selector_evals, selected_rank_evals) =
            Self::terminal_npo_tip5_lookup_selected_npo_io_lane_selector_rank_evals(columns)?;
        let (packed_lane_selector_evals, packed_rank_evals) =
            Self::terminal_npo_tip5_packed_lookup_npo_io_lane_selector_rank_evals(
                columns,
                packed_trace_profile,
            )?;

        let (pcs, mut challenger) =
            Self::terminal_fri_pcs_and_challenger(selected_profile.proximity)?;
        let selected_domain = <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::natural_domain_for_degree(
            &pcs, selected_profile.padded_rows
        );
        let packed_domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                packed_trace_profile.padded_rows,
            );
        let projection_quotient_domain =
            packed_domain.create_disjoint_domain(projection_quotient_profile.padded_rows);
        let selected_bridge_quotient_domain =
            selected_domain.create_disjoint_domain(selected_bridge_quotient_profile.padded_rows);
        let packed_bridge_quotient_domain =
            packed_domain.create_disjoint_domain(packed_bridge_quotient_profile.padded_rows);

        let selected_lookup_commitment = selected_lookup.selected_lookup_commitment.clone();
        let selected_lookup_data = &selected_lookup.selected_lookup_data;
        let selected_lookup_commitment_digest = selected_lookup.commitment_digest;
        let (packed_trace_commitment, packed_trace_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(packed_domain, packed_trace.clone())],
            );
        let (packed_npo_io_commitment, packed_npo_io_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(packed_domain, packed_npo_io_matrix.clone())],
            );
        let packed_trace_commitment_digest =
            Self::terminal_fri_commitment_digest(&packed_trace_commitment)?;
        let packed_npo_io_commitment_digest =
            Self::terminal_fri_commitment_digest(&packed_npo_io_commitment)?;
        Self::verify_terminal_fri_prelude_commitments(
            prelude,
            &[
                selected_lookup_commitment_digest,
                packed_trace_commitment_digest,
                packed_npo_io_commitment_digest,
            ],
        )?;

        Self::seed_terminal_npo_tip5_packed_lookup_npo_io_projection_selected_bridge_challenger(
            &mut challenger,
            prelude,
            &selected_profile,
            &lookup_io_profile,
            packed_trace_profile,
            &packed_npo_io_profile,
            &projection_quotient_profile,
            &selected_accumulator_profile,
            &packed_accumulator_profile,
            &selected_bridge_quotient_profile,
            &packed_bridge_quotient_profile,
        );
        challenger.observe(selected_lookup_commitment.clone());
        challenger.observe(packed_trace_commitment.clone());
        challenger.observe(packed_npo_io_commitment.clone());
        let projection_alpha: TerminalFriChallenge = challenger.sample_algebra_element();
        let bridge_alpha: TerminalFriChallenge = challenger.sample_algebra_element();
        let bridge_beta_rank: TerminalFriChallenge = challenger.sample_algebra_element();
        let bridge_beta_limb: TerminalFriChallenge = challenger.sample_algebra_element();

        let projection_quotient_matrix =
            Self::terminal_npo_tip5_packed_lookup_npo_io_projection_quotient_matrix_goldilocks(
                packed_domain,
                projection_quotient_domain,
                packed_trace_profile,
                packed_trace,
                &packed_npo_io_profile,
                &packed_npo_io_matrix,
                projection_alpha,
            )?;
        let (projection_quotient_commitment, projection_quotient_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(projection_quotient_domain, projection_quotient_matrix)],
            );

        let (selected_accumulator_matrix, selected_final_cumulatives) =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_accumulator_matrix_goldilocks(
                selected_lookup_matrix,
                selected_profile.basis_columns,
                selected_profile.rows,
                selected_profile.padded_rows,
                &selected_lane_selector_evals,
                &selected_rank_evals,
                TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
            )?;
        let (packed_accumulator_matrix, packed_final_cumulatives) =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_accumulator_matrix_goldilocks(
                &packed_npo_io_matrix,
                0,
                packed_npo_io_profile.rows,
                packed_npo_io_profile.padded_rows,
                &packed_lane_selector_evals,
                &packed_rank_evals,
                -TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
            )?;
        for (selected, packed) in selected_final_cumulatives
            .iter()
            .zip(packed_final_cumulatives.iter())
        {
            if *selected + *packed != TerminalFriChallenge::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                        label: "tip5_packed_projection_selected_bridge_final".into(),
                    },
                );
            }
        }
        let (selected_accumulator_commitment, selected_accumulator_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(selected_domain, selected_accumulator_matrix.clone())],
            );
        let (packed_accumulator_commitment, packed_accumulator_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(packed_domain, packed_accumulator_matrix.clone())],
            );
        challenger.observe(projection_quotient_commitment.clone());
        challenger.observe(selected_accumulator_commitment.clone());
        challenger.observe(packed_accumulator_commitment.clone());
        challenger.observe_algebra_slice(&selected_final_cumulatives);
        challenger.observe_algebra_slice(&packed_final_cumulatives);
        let bridge_gamma: TerminalFriChallenge = challenger.sample_algebra_element();

        let selected_bridge_quotient_matrix =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_quotient_matrix_goldilocks(
                selected_domain,
                selected_bridge_quotient_domain,
                selected_lookup_matrix,
                &selected_accumulator_matrix,
                &selected_final_cumulatives,
                &selected_lane_selector_evals,
                &selected_rank_evals,
                selected_profile.basis_columns,
                selected_profile.rows,
                selected_profile.padded_rows,
                TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
                bridge_gamma,
            )?;
        let packed_bridge_quotient_matrix =
            Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_quotient_matrix_goldilocks(
                packed_domain,
                packed_bridge_quotient_domain,
                &packed_npo_io_matrix,
                &packed_accumulator_matrix,
                &packed_final_cumulatives,
                &packed_lane_selector_evals,
                &packed_rank_evals,
                0,
                packed_npo_io_profile.rows,
                packed_npo_io_profile.padded_rows,
                -TerminalFriChallenge::ONE,
                bridge_alpha,
                bridge_beta_rank,
                bridge_beta_limb,
                bridge_gamma,
            )?;
        let (selected_bridge_quotient_commitment, selected_bridge_quotient_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(selected_bridge_quotient_domain, selected_bridge_quotient_matrix)],
            );
        let (packed_bridge_quotient_commitment, packed_bridge_quotient_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(packed_bridge_quotient_domain, packed_bridge_quotient_matrix)],
            );
        challenger.observe(selected_bridge_quotient_commitment.clone());
        challenger.observe(packed_bridge_quotient_commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let selected_next_zeta = selected_domain.next_point(zeta).ok_or_else(|| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: "terminal packed projection+selected bridge selected domain has no successor"
                    .into(),
            }
        })?;
        let packed_next_zeta = packed_domain.next_point(zeta).ok_or_else(|| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: "terminal packed projection+selected bridge packed domain has no successor"
                    .into(),
            }
        })?;

        let (opened_values, plain_proof) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::open(
                &pcs,
                vec![
                    (selected_lookup_data, vec![vec![zeta]]),
                    (&packed_trace_data, vec![vec![zeta]]),
                    (&packed_npo_io_data, vec![vec![zeta]]),
                    (&projection_quotient_data, vec![vec![zeta]]),
                    (
                        &selected_accumulator_data,
                        vec![vec![zeta, selected_next_zeta]],
                    ),
                    (
                        &packed_accumulator_data,
                        vec![vec![zeta, packed_next_zeta]],
                    ),
                    (&selected_bridge_quotient_data, vec![vec![zeta]]),
                    (&packed_bridge_quotient_data, vec![vec![zeta]]),
                ],
                &mut challenger,
            );
        let opened_selected_lookup_basis =
            Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 0)?;
        let opened_packed_trace_basis =
            Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 1)?;
        let opened_packed_npo_io_basis =
            Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 2)?;
        let opened_projection_quotient_basis =
            Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 3)?;
        let opened_selected_accumulator_points_basis =
            Self::terminal_npo_opened_matrix_points_basis_u64(&opened_values, 4)?;
        let opened_packed_accumulator_points_basis =
            Self::terminal_npo_opened_matrix_points_basis_u64(&opened_values, 5)?;
        let opened_selected_bridge_quotient_basis =
            Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 6)?;
        let opened_packed_bridge_quotient_basis =
            Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 7)?;

        let mut query_challenger = TerminalFriChallenger::new(Tip5Perm);
        Self::seed_terminal_npo_tip5_packed_lookup_npo_io_projection_selected_bridge_challenger(
            &mut query_challenger,
            prelude,
            &selected_profile,
            &lookup_io_profile,
            packed_trace_profile,
            &packed_npo_io_profile,
            &projection_quotient_profile,
            &selected_accumulator_profile,
            &packed_accumulator_profile,
            &selected_bridge_quotient_profile,
            &packed_bridge_quotient_profile,
        );
        query_challenger.observe(selected_lookup_commitment.clone());
        query_challenger.observe(packed_trace_commitment.clone());
        query_challenger.observe(packed_npo_io_commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe(projection_quotient_commitment.clone());
        query_challenger.observe(selected_accumulator_commitment.clone());
        query_challenger.observe(packed_accumulator_commitment.clone());
        query_challenger.observe_algebra_slice(&selected_final_cumulatives);
        query_challenger.observe_algebra_slice(&packed_final_cumulatives);
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe(selected_bridge_quotient_commitment.clone());
        query_challenger.observe(packed_bridge_quotient_commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        for matrix in &opened_values {
            for round in matrix {
                for point_values in round {
                    query_challenger.observe_algebra_slice(point_values);
                }
            }
        }
        let query_indices = Self::derive_terminal_fri_query_indices_from_challenger(
            &mut query_challenger,
            &plain_proof,
            selected_profile.proximity,
        )?;
        let proof = Self::compress_terminal_fri_proof(&plain_proof, &query_indices)?;

        Ok(
            TerminalNpoTip5PackedLookupNpoIoProjectionSelectedBridgeProof {
                selected_profile,
                lookup_io_profile,
                packed_trace_profile: packed_trace_profile.clone(),
                packed_npo_io_profile,
                projection_quotient_profile,
                selected_accumulator_profile,
                packed_accumulator_profile,
                selected_bridge_quotient_profile,
                packed_bridge_quotient_profile,
                selected_lookup_commitment,
                packed_trace_commitment,
                packed_npo_io_commitment,
                projection_quotient_commitment,
                selected_accumulator_commitment,
                packed_accumulator_commitment,
                selected_bridge_quotient_commitment,
                packed_bridge_quotient_commitment,
                selected_final_cumulative_basis: selected_final_cumulatives
                    .iter()
                    .map(Self::goldilocks_basis_u64)
                    .collect(),
                packed_final_cumulative_basis: packed_final_cumulatives
                    .iter()
                    .map(Self::goldilocks_basis_u64)
                    .collect(),
                opened_selected_lookup_basis,
                opened_packed_trace_basis,
                opened_packed_npo_io_basis,
                opened_projection_quotient_basis,
                opened_selected_accumulator_points_basis,
                opened_packed_accumulator_points_basis,
                opened_selected_bridge_quotient_basis,
                opened_packed_bridge_quotient_basis,
                proof,
            },
        )
    }

    pub fn prove_terminal_npo_tip5_packed_lookup_logup_quotient_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
        prelude: &TerminalProofPrelude,
    ) -> Result<TerminalNpoTip5PackedLookupLogupQuotientProof, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        self.verify_proof_prelude_goldilocks(verifying_key, public_inputs, prelude)?;
        let (_, trace_profile, trace) =
            self.terminal_npo_tip5_packed_lookup_trace_goldilocks(verifying_key, witness)?;
        Self::prove_terminal_npo_tip5_packed_lookup_logup_quotient_from_trace_goldilocks(
            prelude,
            &trace_profile,
            &trace,
        )
    }

    fn prove_terminal_npo_tip5_packed_lookup_logup_quotient_from_trace_goldilocks(
        prelude: &TerminalProofPrelude,
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<TerminalNpoTip5PackedLookupLogupQuotientProof, NativeTerminalVerifyError>
    {
        let table_matrix =
            Self::terminal_npo_tip5_packed_lookup_logup_table_multiplicity_matrix_goldilocks(
                trace_profile,
                trace,
            )?;
        Self::prove_terminal_npo_tip5_packed_lookup_logup_quotient_from_trace_and_table_goldilocks(
            prelude,
            trace_profile,
            trace,
            &table_matrix,
        )
    }

    fn prove_terminal_npo_tip5_packed_lookup_logup_quotient_from_trace_and_table_goldilocks(
        prelude: &TerminalProofPrelude,
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &RowMajorMatrix<Goldilocks>,
        table_matrix: &RowMajorMatrix<Goldilocks>,
    ) -> Result<TerminalNpoTip5PackedLookupLogupQuotientProof, NativeTerminalVerifyError>
    {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(trace_profile, trace)?;
        if trace_profile.proximity != prelude.relation_profile.proximity {
            return Err(
                NativeTerminalVerifyError::TerminalProximityParametersMismatch {
                    expected: prelude.relation_profile.proximity.proof_parameters(),
                    got: trace_profile.proximity.proof_parameters(),
                },
            );
        }
        let table_profile =
            Self::terminal_npo_tip5_packed_lookup_logup_table_profile(trace_profile)?;
        Self::validate_terminal_npo_tip5_packed_lookup_logup_table_matrix(
            &table_profile,
            table_matrix,
        )?;
        let accumulator_profile =
            Self::terminal_npo_tip5_packed_lookup_logup_accumulator_profile(trace_profile)?;
        let quotient_profile =
            Self::terminal_npo_tip5_packed_lookup_logup_quotient_profile(trace_profile)?;

        let (pcs, mut challenger) =
            Self::terminal_fri_pcs_and_challenger(trace_profile.proximity)?;
        let trace_domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                trace_profile.padded_rows,
            );
        let (trace_commitment, trace_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(trace_domain, trace.clone())],
            );
        let trace_commitment_digest = Self::terminal_fri_commitment_digest(&trace_commitment)?;
        Self::verify_terminal_fri_prelude_commitments(prelude, &[trace_commitment_digest])?;
        let (table_commitment, table_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(trace_domain, table_matrix.clone())],
            );

        Self::seed_terminal_npo_tip5_packed_lookup_logup_quotient_challenger(
            &mut challenger,
            prelude,
            trace_profile,
            &table_profile,
            &accumulator_profile,
            &quotient_profile,
        );
        challenger.observe(trace_commitment.clone());
        challenger.observe(table_commitment.clone());
        let alpha: TerminalFriChallenge = challenger.sample_algebra_element();
        let beta: TerminalFriChallenge = challenger.sample_algebra_element();
        let challenges =
            vec![(alpha, beta); Self::terminal_npo_tip5_packed_lookup_logup_interactions()];

        let (accumulator_matrix, final_cumulatives) =
            Self::terminal_npo_tip5_packed_lookup_logup_accumulator_matrix_goldilocks(
                trace_profile,
                trace,
                table_matrix,
                &challenges,
            )?;
        let (accumulator_commitment, accumulator_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(trace_domain, accumulator_matrix.clone())],
            );
        challenger.observe(accumulator_commitment.clone());
        challenger.observe_algebra_slice(&final_cumulatives);
        let gamma: TerminalFriChallenge = challenger.sample_algebra_element();

        let quotient_domain = trace_domain.create_disjoint_domain(quotient_profile.padded_rows);
        let quotient_matrix =
            Self::terminal_npo_tip5_packed_lookup_logup_quotient_matrix_goldilocks(
                trace_domain,
                quotient_domain,
                trace_profile,
                trace,
                &table_profile,
                table_matrix,
                &accumulator_matrix,
                &final_cumulatives,
                &challenges,
                gamma,
            )?;
        let (quotient_commitment, quotient_data) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::commit(
                &pcs,
                [(quotient_domain, quotient_matrix)],
            );
        challenger.observe(quotient_commitment.clone());
        let zeta: TerminalFriChallenge = challenger.sample_algebra_element();
        let next_zeta = trace_domain.next_point(zeta).ok_or_else(|| {
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: "terminal packed Tip5 LogUp opening domain has no successor".into(),
            }
        })?;
        let (opened_values, plain_proof) =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::open(
                &pcs,
                vec![
                    (&trace_data, vec![vec![zeta]]),
                    (&table_data, vec![vec![zeta]]),
                    (&accumulator_data, vec![vec![zeta, next_zeta]]),
                    (&quotient_data, vec![vec![zeta]]),
                ],
                &mut challenger,
            );
        let opened_trace_basis = Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 0)?;
        let opened_table_basis = Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 1)?;
        let opened_accumulator_points_basis =
            Self::terminal_npo_opened_matrix_points_basis_u64(&opened_values, 2)?;
        let opened_quotient_basis = Self::terminal_npo_opened_matrix_basis_u64(&opened_values, 3)?;

        let mut query_challenger = TerminalFriChallenger::new(Tip5Perm);
        Self::seed_terminal_npo_tip5_packed_lookup_logup_quotient_challenger(
            &mut query_challenger,
            prelude,
            trace_profile,
            &table_profile,
            &accumulator_profile,
            &quotient_profile,
        );
        query_challenger.observe(trace_commitment.clone());
        query_challenger.observe(table_commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe(accumulator_commitment.clone());
        query_challenger.observe_algebra_slice(&final_cumulatives);
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        query_challenger.observe(quotient_commitment.clone());
        let _: TerminalFriChallenge = query_challenger.sample_algebra_element();
        for matrix in &opened_values {
            for round in matrix {
                for point_values in round {
                    query_challenger.observe_algebra_slice(point_values);
                }
            }
        }
        let query_indices = Self::derive_terminal_fri_query_indices_from_challenger(
            &mut query_challenger,
            &plain_proof,
            trace_profile.proximity,
        )?;
        let proof = Self::compress_terminal_fri_proof(&plain_proof, &query_indices)?;

        Ok(TerminalNpoTip5PackedLookupLogupQuotientProof {
            trace_profile: trace_profile.clone(),
            table_profile,
            accumulator_profile,
            quotient_profile,
            trace_commitment,
            table_commitment,
            accumulator_commitment,
            quotient_commitment,
            final_cumulative_basis: final_cumulatives
                .iter()
                .map(Self::goldilocks_basis_u64)
                .collect(),
            opened_trace_basis,
            opened_table_basis,
            opened_accumulator_points_basis,
            opened_quotient_basis,
            proof,
        })
    }

