    fn validate_terminal_npo_polynomial_column_evaluation_commitments<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        prelude: &TerminalProofPrelude,
        proof: &TerminalNpoPolynomialColumnEvaluationProof,
        require_exact_single_prelude: bool,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let layout = Self::terminal_npo_polynomial_column_layout::<F>(verifying_key);
        let labels = Self::terminal_npo_polynomial_column_labels(&layout);
        if !labels.iter().any(|label| label == &proof.column_label) {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnMissing {
                    label: proof.column_label.clone(),
                },
            );
        }
        let expected_label = Self::terminal_npo_polynomial_column_oracle_label(&proof.column_label);
        if proof.column_commitment.label != expected_label {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLabelMismatch {
                    expected: expected_label,
                    got: proof.column_commitment.label.clone(),
                },
            );
        }
        if proof.column_commitment.values_len != layout.rows {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLengthMismatch {
                    label: proof.column_commitment.label.clone(),
                    expected: layout.rows,
                    got: proof.column_commitment.values_len,
                },
            );
        }
        if require_exact_single_prelude {
            Self::verify_npo_polynomial_column_prelude_commitments(
                prelude,
                core::slice::from_ref(&proof.column_commitment),
            )?;
        } else {
            Self::verify_prelude_binds_commitment(prelude, &proof.column_commitment)?;
        }

        let mut len = proof.column_commitment.values_len;
        let mut expected_rounds = 0usize;
        while len > 1 {
            len = len.div_ceil(2);
            expected_rounds += 1;
        }
        if proof.fold_commitments.len() != expected_rounds {
            return Err(
                NativeTerminalVerifyError::TerminalResidualFoldCommitmentLengthMismatch {
                    round: expected_rounds,
                    expected: expected_rounds,
                    got: proof.fold_commitments.len(),
                },
            );
        }
        let mut current_len = proof.column_commitment.values_len;
        for (round, commitment) in proof.fold_commitments.iter().enumerate() {
            let expected_len = current_len.div_ceil(2);
            if commitment.values_len != expected_len {
                return Err(
                    NativeTerminalVerifyError::TerminalResidualFoldCommitmentLengthMismatch {
                        round,
                        expected: expected_len,
                        got: commitment.values_len,
                    },
                );
            }
            let expected_label =
                Self::npo_polynomial_column_fold_oracle_label(&proof.column_label, round);
            if commitment.label != expected_label {
                return Err(
                    NativeTerminalVerifyError::TerminalResidualFoldCommitmentLabelMismatch {
                        round,
                        expected: expected_label,
                        got: commitment.label.clone(),
                    },
                );
            }
            current_len = expected_len;
        }
        Ok(())
    }

    fn validate_terminal_npo_polynomial_combined_evaluation_commitments(
        combined_commitment: &TerminalOracleCommitment,
        fold_commitments: &[TerminalOracleCommitment],
        rows: usize,
    ) -> Result<(), NativeTerminalVerifyError> {
        let expected_label = Self::npo_polynomial_combined_column_oracle_label();
        if combined_commitment.label != expected_label {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLabelMismatch {
                    expected: expected_label.into(),
                    got: combined_commitment.label.clone(),
                },
            );
        }
        if combined_commitment.values_len != rows {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLengthMismatch {
                    label: combined_commitment.label.clone(),
                    expected: rows,
                    got: combined_commitment.values_len,
                },
            );
        }
        let mut len = combined_commitment.values_len;
        let mut expected_rounds = 0usize;
        while len > 1 {
            len = len.div_ceil(2);
            expected_rounds += 1;
        }
        if fold_commitments.len() != expected_rounds {
            return Err(
                NativeTerminalVerifyError::TerminalResidualFoldCommitmentLengthMismatch {
                    round: expected_rounds,
                    expected: expected_rounds,
                    got: fold_commitments.len(),
                },
            );
        }
        let mut current_len = combined_commitment.values_len;
        for (round, commitment) in fold_commitments.iter().enumerate() {
            let expected_len = current_len.div_ceil(2);
            if commitment.values_len != expected_len {
                return Err(
                    NativeTerminalVerifyError::TerminalResidualFoldCommitmentLengthMismatch {
                        round,
                        expected: expected_len,
                        got: commitment.values_len,
                    },
                );
            }
            let expected_label = Self::npo_polynomial_combined_column_fold_oracle_label(round);
            if commitment.label != expected_label {
                return Err(
                    NativeTerminalVerifyError::TerminalResidualFoldCommitmentLabelMismatch {
                        round,
                        expected: expected_label,
                        got: commitment.label.clone(),
                    },
                );
            }
            current_len = expected_len;
        }
        Ok(())
    }

    fn validate_terminal_npo_polynomial_residual_zero_commitments(
        combined_residual_commitment: &TerminalOracleCommitment,
        fold_commitments: &[TerminalOracleCommitment],
        rows: usize,
    ) -> Result<(), NativeTerminalVerifyError> {
        let expected_label = Self::npo_polynomial_combined_residual_oracle_label();
        if combined_residual_commitment.label != expected_label {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLabelMismatch {
                    expected: expected_label.into(),
                    got: combined_residual_commitment.label.clone(),
                },
            );
        }
        if combined_residual_commitment.values_len != rows {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLengthMismatch {
                    label: combined_residual_commitment.label.clone(),
                    expected: rows,
                    got: combined_residual_commitment.values_len,
                },
            );
        }
        let mut len = combined_residual_commitment.values_len;
        let mut expected_rounds = 0usize;
        while len > 1 {
            len = len.div_ceil(2);
            expected_rounds += 1;
        }
        if fold_commitments.len() != expected_rounds {
            return Err(
                NativeTerminalVerifyError::TerminalResidualFoldCommitmentLengthMismatch {
                    round: expected_rounds,
                    expected: expected_rounds,
                    got: fold_commitments.len(),
                },
            );
        }
        let mut current_len = combined_residual_commitment.values_len;
        for (round, commitment) in fold_commitments.iter().enumerate() {
            let expected_len = current_len.div_ceil(2);
            if commitment.values_len != expected_len {
                return Err(
                    NativeTerminalVerifyError::TerminalResidualFoldCommitmentLengthMismatch {
                        round,
                        expected: expected_len,
                        got: commitment.values_len,
                    },
                );
            }
            let expected_label = Self::npo_polynomial_combined_residual_fold_oracle_label(round);
            if commitment.label != expected_label {
                return Err(
                    NativeTerminalVerifyError::TerminalResidualFoldCommitmentLabelMismatch {
                        round,
                        expected: expected_label,
                        got: commitment.label.clone(),
                    },
                );
            }
            current_len = expected_len;
        }
        Ok(())
    }

    pub fn commit_terminal_combined_validity_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
    ) -> Result<TerminalOracleMerkleTree, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        let values = self.terminal_combined_validity_values_goldilocks(
            verifying_key,
            public_inputs,
            witness,
        )?;
        TerminalOracleMerkleTree::commit_goldilocks_values(
            Self::combined_validity_oracle_label(),
            &values,
        )
    }

    pub fn terminal_combined_validity_values_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        public_inputs: &[F],
        witness: &TerminalWitness<F>,
    ) -> Result<Vec<F>, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        let mut values = self.terminal_quadratic_residual_values_goldilocks(
            verifying_key,
            public_inputs,
            witness,
        )?;
        values.extend(self.terminal_npo_validity_values_goldilocks(verifying_key, witness)?);
        Ok(values)
    }

    pub fn derive_terminal_combined_validity_fold_query_plan(
        &self,
        prelude: &TerminalProofPrelude,
        combined_commitment: &TerminalOracleCommitment,
        fold_commitments: &[TerminalOracleCommitment],
    ) -> Result<TerminalQueryPlan, NativeTerminalVerifyError> {
        if combined_commitment.values_len == 0 {
            return Err(NativeTerminalVerifyError::TerminalQuadraticResidualQueryDomainEmpty);
        }

        let num_queries = prelude.parameters.num_queries as usize;
        let mut indices = Vec::with_capacity(num_queries);
        let mut counter = 0u64;
        while indices.len() < num_queries {
            if counter
                > (num_queries as u64)
                    .saturating_mul(4096)
                    .saturating_add(4096)
            {
                return Err(NativeTerminalVerifyError::TerminalQueryDerivationLimitExceeded);
            }
            let block = Self::terminal_combined_validity_fold_query_block(
                prelude,
                combined_commitment,
                fold_commitments,
                counter,
            );
            for limb in block {
                if indices.len() == num_queries {
                    break;
                }
                let bound = combined_commitment.values_len as u64;
                let zone = u64::MAX - (u64::MAX % bound);
                if limb < zone {
                    Self::accept_terminal_query_index(
                        &mut indices,
                        (limb % bound) as usize,
                        combined_commitment.values_len,
                        num_queries,
                    );
                }
            }
            counter += 1;
        }

        Ok(TerminalQueryPlan {
            oracle_label: combined_commitment.label.clone(),
            oracle_len: combined_commitment.values_len,
            indices,
        })
    }

