    fn terminal_npo_tip5_lookup_air_fold_constants() -> TerminalNpoTip5LookupAirFoldConstants {
        let fe = |value: u64| TerminalFriChallenge::from(Goldilocks::from_u64(value));
        let raw_mds = tip5_mds_matrix();
        TerminalNpoTip5LookupAirFoldConstants {
            mds: core::array::from_fn(|row| {
                core::array::from_fn(|column| fe(raw_mds[row][column]))
            }),
            round_constants: core::array::from_fn(|round| {
                core::array::from_fn(|lane| {
                    fe(tip5_rc_precomp(
                        TIP5_ROUND_CONSTANTS[round * 16 + lane],
                    ))
                })
            }),
            pow8: core::array::from_fn(|byte| fe(1u64 << (8 * byte))),
            two32_minus_one: fe((1u64 << 32) - 1),
        }
    }

    fn terminal_npo_tip5_lookup_air_algebra_quotient_matrix_goldilocks(
        trace_domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        quotient_domain: <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::Domain,
        trace_profile: &TerminalNpoTip5LookupFriProfile,
        trace_matrix: &RowMajorMatrix<Goldilocks>,
        alpha: TerminalFriChallenge,
        beta: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        if trace_profile.column_set != TerminalNpoTip5LookupFriColumnSet::FullMain {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_trace_column_set".into(),
                    expected: TerminalNpoTip5LookupFriColumnSet::FullMain as usize,
                    got: trace_profile.column_set as usize,
                },
            );
        }
        if trace_matrix.width() != trace_profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_trace_width".into(),
                    expected: trace_profile.basis_columns,
                    got: trace_matrix.width(),
                },
            );
        }
        if trace_matrix.height() != trace_profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_trace_rows".into(),
                    expected: trace_profile.padded_rows,
                    got: trace_matrix.height(),
                },
            );
        }
        let quotient_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let preprocessed_evals = (0..Self::TIP5_LOOKUP_PREPROCESSED_WIDTH)
            .map(|column| {
                Self::terminal_npo_tip5_lookup_preprocessed_column_evals(
                    &trace_profile.trace,
                    column,
                )
            })
            .collect::<Result<Vec<_>, _>>()?;
        let trace_width = trace_profile.basis_columns;
        let preprocessed_width = Self::TIP5_LOOKUP_PREPROCESSED_WIDTH;
        if trace_width != tip5_lookup_air_width() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_required_trace_width".into(),
                    expected: tip5_lookup_air_width(),
                    got: trace_width,
                },
            );
        }
        let lde_width = trace_width + preprocessed_width;
        let mut lde_values = Vec::with_capacity(trace_profile.padded_rows * lde_width);
        for row in 0..trace_profile.padded_rows {
            let trace_start = row * trace_width;
            lde_values
                .extend_from_slice(&trace_matrix.values[trace_start..trace_start + trace_width]);
            for evals in &preprocessed_evals {
                lde_values.push(evals[row]);
            }
        }
        let lde_matrix = Self::terminal_coset_lde_matrix_goldilocks(
            "tip5_lookup_air_algebra_quotient",
            trace_domain,
            quotient_domain,
            RowMajorMatrix::new(lde_values, lde_width),
        )?;
        if lde_matrix.width() != lde_width {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: lde_width,
                    got: lde_matrix.width(),
                },
            );
        }
        let next_row_stride = quotient_domain
            .size()
            .checked_div(trace_domain.size())
            .filter(|ratio| ratio.is_power_of_two())
            .ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_quotient_lde_stride".into(),
                    expected: trace_domain.size() * 2,
                    got: quotient_domain.size(),
                },
            )?;
        let quotient_domain_size = quotient_domain.size();
        tracing::info!(
            trace_rows = trace_profile.padded_rows,
            quotient_rows = quotient_domain_size,
            trace_width,
            preprocessed_width,
            lde_width,
            "terminal Tip5 AIR algebra quotient shape"
        );
        let fold_constants = Self::terminal_npo_tip5_lookup_air_fold_constants();
        let mut quotient_points = Vec::with_capacity(quotient_domain_size);
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain_size {
            quotient_points.push(point);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal Tip5 lookup AIR algebra quotient domain has no successor"
                        .into(),
                }
            })?;
        }
        let quotient_values = quotient_points
            .into_par_iter()
            .enumerate()
            .map(|(row, point)| -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
                let row_base = row * lde_width;
                let next_row = (row + next_row_stride) % quotient_domain_size;
                let next_row_base = next_row * lde_width;
                let mut opened_trace = [TerminalFriChallenge::ZERO; tip5_lookup_air_width()];
                let mut opened_next_trace = [TerminalFriChallenge::ZERO; tip5_lookup_air_width()];
                let mut preprocessed =
                    [TerminalFriChallenge::ZERO; Self::TIP5_LOOKUP_PREPROCESSED_WIDTH];
                for column in 0..trace_width {
                    opened_trace[column] = TerminalFriChallenge::from(
                        lde_matrix.values[row_base + column],
                    );
                    opened_next_trace[column] = TerminalFriChallenge::from(
                        lde_matrix.values[next_row_base + column],
                    );
                }
                for column in 0..preprocessed_width {
                    preprocessed[column] = TerminalFriChallenge::from(
                        lde_matrix.values[row_base + trace_width + column],
                    );
                }
                let relation = Self::terminal_npo_tip5_lookup_air_algebra_folded_relation(
                    &opened_trace,
                    &opened_next_trace,
                    &preprocessed,
                    alpha,
                    &fold_constants,
                )?;
                let terminal_io =
                    Self::terminal_npo_tip5_lookup_air_terminal_io_folded_relation(
                        &opened_trace,
                        trace_profile,
                        alpha,
                    )?;
                let window_vanishing =
                    Self::terminal_npo_tip5_lookup_permutation_window_vanishing_at_point(
                        trace_domain,
                        trace_profile,
                        point,
                    )?;
                let relation = relation + beta * window_vanishing * terminal_io;
                Ok(relation / trace_domain.vanishing_poly_at_point(point))
            })
            .collect::<Result<Vec<_>, _>>()?;
        let quotient = RowMajorMatrix::new_col(quotient_values).flatten_to_base();
        if quotient.width() != quotient_basis_dimension {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: quotient_basis_dimension,
                    got: quotient.width(),
                },
            );
        }
        Ok(quotient)
    }

    fn terminal_npo_tip5_lookup_air_algebra_folded_relation(
        trace: &[TerminalFriChallenge],
        next_trace: &[TerminalFriChallenge],
        preprocessed: &[TerminalFriChallenge],
        alpha: TerminalFriChallenge,
        constants: &TerminalNpoTip5LookupAirFoldConstants,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        const STATE_SIZE: usize = 16;

        let required_width = tip5_lookup_air_width();
        if trace.len() != required_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_opened_trace_width".into(),
                    expected: required_width,
                    got: trace.len(),
                },
            );
        }
        if next_trace.len() != required_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_algebra_opened_next_trace_width".into(),
                    expected: required_width,
                    got: next_trace.len(),
                },
            );
        }
        if preprocessed.len() != Self::TIP5_LOOKUP_PREPROCESSED_WIDTH {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: Self::TIP5_LOOKUP_PREPROCESSED_WIDTH,
                    got: preprocessed.len(),
                },
            );
        }
        let mut folded = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        let mut absorb = |constraint: TerminalFriChallenge| {
            folded += coeff * constraint;
            coeff *= alpha;
        };

        let is_table = preprocessed[Self::TIP5_LOOKUP_P_IS_TABLE];
        let is_round = preprocessed[Self::TIP5_LOOKUP_P_IS_ROUND];
        let link_next = (0..TIP5_PERM_ROUNDS - 1)
            .map(|round| preprocessed[Self::TIP5_LOOKUP_P_ROUND0 + round])
            .sum::<TerminalFriChallenge>();
        absorb((TerminalFriChallenge::ONE - is_table) * trace[Self::TIP5_LOOKUP_C_TMULT]);

        let mut sbox_outputs = [TerminalFriChallenge::ZERO; STATE_SIZE];
        for lane in 0..Self::TIP5_LOOKUP_NS {
            let mut recompose_b = TerminalFriChallenge::ZERO;
            let mut recompose_c = TerminalFriChallenge::ZERO;
            let mut low = TerminalFriChallenge::ZERO;
            let mut high = TerminalFriChallenge::ZERO;
            for byte in 0..Self::TIP5_LOOKUP_NBYTES {
                let b = trace[Self::terminal_npo_tip5_lookup_b_col(lane, byte)];
                let c = trace[Self::terminal_npo_tip5_lookup_c_col(lane, byte)];
                recompose_b += b * constants.pow8[byte];
                recompose_c += c * constants.pow8[byte];
                if byte < 4 {
                    low += b * constants.pow8[byte];
                } else {
                    high += b * constants.pow8[byte - 4];
                }
            }
            absorb(is_round * (recompose_b - trace[Self::TIP5_LOOKUP_C_IN + lane]));
            sbox_outputs[lane] = recompose_c;

            let g = high - constants.two32_minus_one;
            let inv = trace[Self::terminal_npo_tip5_lookup_inv_col(lane)];
            let prod = g * inv;
            absorb(is_round * g * (prod - TerminalFriChallenge::ONE));
            absorb(is_round * (TerminalFriChallenge::ONE - prod) * low);
        }

        for lane in Self::TIP5_LOOKUP_NS..STATE_SIZE {
            let x = trace[Self::TIP5_LOOKUP_C_IN + lane];
            let x2 = x * x;
            let x3 = x2 * x;
            sbox_outputs[lane] = x3 * x3 * x;
        }

        for lane in 0..STATE_SIZE {
            let mut acc = TerminalFriChallenge::ZERO;
            for column in 0..STATE_SIZE {
                acc += constants.mds[lane][column] * sbox_outputs[column];
            }
            let mut rc = TerminalFriChallenge::ZERO;
            for round in 0..TIP5_PERM_ROUNDS {
                rc += preprocessed[Self::TIP5_LOOKUP_P_ROUND0 + round]
                    * constants.round_constants[round][lane];
            }
            absorb(is_round * (trace[Self::terminal_npo_tip5_lookup_out_col(lane)] - acc - rc));
            absorb(
                preprocessed[Self::TIP5_LOOKUP_P_ROUND0]
                    * (trace[Self::TIP5_LOOKUP_C_TIN + lane]
                        - trace[Self::TIP5_LOOKUP_C_IN + lane]),
            );
            absorb(
                link_next
                    * (trace[Self::terminal_npo_tip5_lookup_out_col(lane)]
                        - next_trace[Self::TIP5_LOOKUP_C_IN + lane]),
            );
            absorb(
                link_next
                    * (trace[Self::TIP5_LOOKUP_C_TIN + lane]
                        - next_trace[Self::TIP5_LOOKUP_C_TIN + lane]),
            );
        }

        Ok(folded)
    }

    fn terminal_npo_tip5_lookup_air_terminal_io_folded_relation(
        trace: &[TerminalFriChallenge],
        profile: &TerminalNpoTip5LookupFriProfile,
        alpha: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        let terminal_io_indices = Self::terminal_npo_tip5_lookup_fri_column_indices(
            profile.trace.main_width,
            TerminalNpoTip5LookupFriColumnSet::TerminalIo,
        )?;
        let mut folded = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        for index in terminal_io_indices {
            let value = trace.get(index).copied().ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_air_terminal_io_opened_trace_width".into(),
                    expected: profile.trace.main_width,
                    got: trace.len(),
                },
            )?;
            folded += coeff * value;
            coeff *= alpha;
        }
        Ok(folded)
    }

    fn validate_terminal_npo_tip5_packed_lookup_trace_matrix(
        profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<(), NativeTerminalVerifyError> {
        if trace.width() != profile.main_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_air_algebra_trace_width".into(),
                    expected: profile.main_width,
                    got: trace.width(),
                },
            );
        }
        if trace.height() != profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_air_algebra_trace_rows".into(),
                    expected: profile.padded_rows,
                    got: trace.height(),
                },
            );
        }
        Ok(())
    }

    fn terminal_npo_tip5_packed_lookup_npo_io_matrix_goldilocks(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<
        (
            TerminalNpoTip5PackedLookupNpoIoProfile,
            RowMajorMatrix<Goldilocks>,
        ),
        NativeTerminalVerifyError,
    > {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(trace_profile, trace)?;
        let profile = Self::terminal_npo_tip5_packed_lookup_npo_io_profile(trace_profile)?;
        let mut values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        for row in 0..profile.padded_rows {
            let trace_base = row * trace.width();
            let io_base = row * profile.basis_columns;
            for limb in 0..16 {
                values[io_base + limb] = trace.values
                    [trace_base + Self::terminal_npo_tip5_packed_lookup_round_input_col(0, limb)];
            }
            for limb in 0..10 {
                values[io_base + 16 + limb] = trace.values[trace_base
                    + Self::terminal_npo_tip5_packed_lookup_round_output_col(
                        TIP5_PERM_ROUNDS - 1,
                        limb,
                    )];
            }
        }
        Ok((
            profile.clone(),
            RowMajorMatrix::new(values, profile.basis_columns),
        ))
    }

    fn terminal_npo_tip5_packed_lookup_npo_io_projection_folded_relation(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        opened_trace: &[TerminalFriChallenge],
        npo_io_profile: &TerminalNpoTip5PackedLookupNpoIoProfile,
        opened_npo_io: &[TerminalFriChallenge],
        alpha: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        if opened_trace.len() != trace_profile.main_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_npo_io_projection_trace_width".into(),
                    expected: trace_profile.main_width,
                    got: opened_trace.len(),
                },
            );
        }
        if opened_npo_io.len() != npo_io_profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_npo_io_projection_io_width".into(),
                    expected: npo_io_profile.basis_columns,
                    got: opened_npo_io.len(),
                },
            );
        }
        if npo_io_profile.basis_columns != 26 {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_npo_io_projection_lanes".into(),
                    expected: 26,
                    got: npo_io_profile.basis_columns,
                },
            );
        }
        let mut relation = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        for limb in 0..16 {
            relation += coeff
                * (opened_npo_io[limb]
                    - opened_trace
                        [Self::terminal_npo_tip5_packed_lookup_round_input_col(0, limb)]);
            coeff *= alpha;
        }
        for limb in 0..10 {
            relation += coeff
                * (opened_npo_io[16 + limb]
                    - opened_trace[Self::terminal_npo_tip5_packed_lookup_round_output_col(
                        TIP5_PERM_ROUNDS - 1,
                        limb,
                    )]);
            coeff *= alpha;
        }
        Ok(relation)
    }

    fn terminal_npo_tip5_packed_lookup_opened_trace_npo_io_values(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        opened_trace: &[TerminalFriChallenge],
    ) -> Result<Vec<TerminalFriChallenge>, NativeTerminalVerifyError> {
        if opened_trace.len() != trace_profile.main_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_trace_npo_io_opened_trace_width".into(),
                    expected: trace_profile.main_width,
                    got: opened_trace.len(),
                },
            );
        }
        let mut values = Vec::with_capacity(26);
        for limb in 0..16 {
            values.push(
                opened_trace[Self::terminal_npo_tip5_packed_lookup_round_input_col(0, limb)],
            );
        }
        for limb in 0..10 {
            values.push(
                opened_trace[Self::terminal_npo_tip5_packed_lookup_round_output_col(
                    TIP5_PERM_ROUNDS - 1,
                    limb,
                )],
            );
        }
        Ok(values)
    }

    fn terminal_npo_tip5_packed_lookup_npo_io_projection_quotient_matrix_goldilocks(
        trace_domain: TerminalFriDomain,
        quotient_domain: TerminalFriDomain,
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace_matrix: &RowMajorMatrix<Goldilocks>,
        npo_io_profile: &TerminalNpoTip5PackedLookupNpoIoProfile,
        npo_io_matrix: &RowMajorMatrix<Goldilocks>,
        alpha: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(trace_profile, trace_matrix)?;
        if npo_io_matrix.width() != npo_io_profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_npo_io_projection_matrix_width".into(),
                    expected: npo_io_profile.basis_columns,
                    got: npo_io_matrix.width(),
                },
            );
        }
        if npo_io_matrix.height() != npo_io_profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_npo_io_projection_matrix_rows".into(),
                    expected: npo_io_profile.padded_rows,
                    got: npo_io_matrix.height(),
                },
            );
        }
        let quotient_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let trace_lde = Self::terminal_coset_lde_matrix_goldilocks(
            "tip5_packed_lookup_npo_io_projection_trace",
            trace_domain,
            quotient_domain,
            trace_matrix.clone(),
        )?;
        let npo_io_lde = Self::terminal_coset_lde_matrix_goldilocks(
            "tip5_packed_lookup_npo_io_projection_io",
            trace_domain,
            quotient_domain,
            npo_io_matrix.clone(),
        )?;
        let mut quotient_points = Vec::with_capacity(quotient_domain.size());
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain.size() {
            quotient_points.push(point);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal packed Tip5 NPO-IO projection quotient domain has no successor"
                        .into(),
                }
            })?;
        }
        let quotient_values = (0..quotient_domain.size())
            .into_par_iter()
            .map(|row| -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
                let trace_start = row * trace_lde.width();
                let opened_trace = trace_lde.values[trace_start..trace_start + trace_lde.width()]
                    .iter()
                    .copied()
                    .map(TerminalFriChallenge::from)
                    .collect::<Vec<_>>();
                let io_start = row * npo_io_lde.width();
                let opened_npo_io = npo_io_lde.values[io_start..io_start + npo_io_lde.width()]
                    .iter()
                    .copied()
                    .map(TerminalFriChallenge::from)
                    .collect::<Vec<_>>();
                let point = quotient_points[row];
                let relation =
                    Self::terminal_npo_tip5_packed_lookup_npo_io_projection_folded_relation(
                        trace_profile,
                        &opened_trace,
                        npo_io_profile,
                        &opened_npo_io,
                        alpha,
                    )?;
                Ok(relation / trace_domain.vanishing_poly_at_point(point))
            })
            .collect::<Result<Vec<_>, _>>()?;
        let quotient = RowMajorMatrix::new_col(quotient_values).flatten_to_base();
        if quotient.width() != quotient_basis_dimension {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: quotient_basis_dimension,
                    got: quotient.width(),
                },
            );
        }
        Ok(quotient)
    }

    fn terminal_npo_tip5_packed_lookup_air_algebra_quotient_matrix_goldilocks(
        trace_domain: TerminalFriDomain,
        quotient_domain: TerminalFriDomain,
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace_matrix: &RowMajorMatrix<Goldilocks>,
        alpha: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(trace_profile, trace_matrix)?;
        let quotient_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let lde_matrix = Self::terminal_coset_lde_matrix_goldilocks(
            "tip5_packed_lookup_air_algebra_quotient",
            trace_domain,
            quotient_domain,
            trace_matrix.clone(),
        )?;
        if lde_matrix.width() != trace_profile.main_width {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: trace_profile.main_width,
                    got: lde_matrix.width(),
                },
            );
        }
        let quotient_domain_size = quotient_domain.size();
        tracing::info!(
            trace_rows = trace_profile.padded_rows,
            quotient_rows = quotient_domain_size,
            trace_width = trace_profile.main_width,
            round_width = trace_profile.round_width,
            "terminal packed Tip5 AIR algebra quotient shape"
        );
        let constants = Self::terminal_npo_tip5_lookup_air_fold_constants();
        let mut quotient_points = Vec::with_capacity(quotient_domain_size);
        let mut point = TerminalFriChallenge::from(quotient_domain.first_point());
        for _ in 0..quotient_domain_size {
            quotient_points.push(point);
            point = quotient_domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal packed Tip5 lookup AIR quotient domain has no successor"
                        .into(),
                }
            })?;
        }
        let trace_width = trace_profile.main_width;
        let quotient_values = quotient_points
            .into_par_iter()
            .enumerate()
            .map(|(row, point)| -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
                let row_base = row * trace_width;
                let opened_trace = (0..trace_width)
                    .map(|column| TerminalFriChallenge::from(lde_matrix.values[row_base + column]))
                    .collect::<Vec<_>>();
                let relation =
                    Self::terminal_npo_tip5_packed_lookup_air_algebra_folded_relation(
                        trace_profile,
                        &opened_trace,
                        alpha,
                        &constants,
                    )?;
                Ok(relation / trace_domain.vanishing_poly_at_point(point))
            })
            .collect::<Result<Vec<_>, _>>()?;
        let quotient = RowMajorMatrix::new_col(quotient_values).flatten_to_base();
        if quotient.width() != quotient_basis_dimension {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: quotient_basis_dimension,
                    got: quotient.width(),
                },
            );
        }
        Ok(quotient)
    }

    fn terminal_npo_tip5_packed_lookup_air_algebra_folded_relation(
        profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &[TerminalFriChallenge],
        alpha: TerminalFriChallenge,
        constants: &TerminalNpoTip5LookupAirFoldConstants,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        const STATE_SIZE: usize = 16;

        if trace.len() != profile.main_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_air_algebra_opened_trace_width".into(),
                    expected: profile.main_width,
                    got: trace.len(),
                },
            );
        }
        let mut folded = TerminalFriChallenge::ZERO;
        let mut coeff = TerminalFriChallenge::ONE;
        let mut absorb = |constraint: TerminalFriChallenge| {
            folded += coeff * constraint;
            coeff *= alpha;
        };

        for round in 0..TIP5_PERM_ROUNDS {
            let mut sbox_outputs = [TerminalFriChallenge::ZERO; STATE_SIZE];
            for lane in 0..Self::TIP5_LOOKUP_NS {
                let mut recompose_b = TerminalFriChallenge::ZERO;
                let mut recompose_c = TerminalFriChallenge::ZERO;
                let mut low = TerminalFriChallenge::ZERO;
                let mut high = TerminalFriChallenge::ZERO;
                for byte in 0..Self::TIP5_LOOKUP_NBYTES {
                    let b = trace[Self::terminal_npo_tip5_packed_lookup_b_col(
                        round, lane, byte,
                    )];
                    let c = trace[Self::terminal_npo_tip5_packed_lookup_c_col(
                        round, lane, byte,
                    )];
                    recompose_b += b * constants.pow8[byte];
                    recompose_c += c * constants.pow8[byte];
                    if byte < 4 {
                        low += b * constants.pow8[byte];
                    } else {
                        high += b * constants.pow8[byte - 4];
                    }
                }
                absorb(
                    recompose_b
                        - trace[Self::terminal_npo_tip5_packed_lookup_round_input_col(
                            round, lane,
                        )],
                );
                sbox_outputs[lane] = recompose_c;

                let g = high - constants.two32_minus_one;
                let inv = trace[Self::terminal_npo_tip5_packed_lookup_inv_col(round, lane)];
                let prod = g * inv;
                absorb(g * (prod - TerminalFriChallenge::ONE));
                absorb((TerminalFriChallenge::ONE - prod) * low);
            }

            for lane in Self::TIP5_LOOKUP_NS..STATE_SIZE {
                let x = trace[Self::terminal_npo_tip5_packed_lookup_round_input_col(round, lane)];
                let x2 = x * x;
                let x3 = x2 * x;
                sbox_outputs[lane] = x3 * x3 * x;
            }

            for lane in 0..STATE_SIZE {
                let mut acc = TerminalFriChallenge::ZERO;
                for column in 0..STATE_SIZE {
                    acc += constants.mds[lane][column] * sbox_outputs[column];
                }
                absorb(
                    trace[Self::terminal_npo_tip5_packed_lookup_round_output_col(round, lane)]
                        - acc
                        - constants.round_constants[round][lane],
                );
                if round > 0 {
                    absorb(
                        trace[Self::terminal_npo_tip5_packed_lookup_round_input_col(
                            round, lane,
                        )] - trace[Self::terminal_npo_tip5_packed_lookup_round_output_col(
                            round - 1,
                            lane,
                        )],
                    );
                }
            }
        }

        Ok(folded)
    }

    fn terminal_npo_tip5_packed_lookup_logup_table_profile(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
    ) -> Result<TerminalNpoTip5PackedLookupLogupTableProfile, NativeTerminalVerifyError> {
        if trace_profile.padded_rows < TIP5_LOOKUP_TABLE_ROWS {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_table_domain_rows".into(),
                    expected: TIP5_LOOKUP_TABLE_ROWS,
                    got: trace_profile.padded_rows,
                },
            );
        }
        Ok(TerminalNpoTip5PackedLookupLogupTableProfile {
            trace: trace_profile.clone(),
            rows: trace_profile.rows,
            padded_rows: trace_profile.padded_rows,
            log_rows: trace_profile.log_rows,
            field_basis_dimension: <Goldilocks as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: 1,
            proximity: trace_profile.proximity,
        })
    }

    fn terminal_npo_tip5_packed_lookup_logup_accumulator_profile(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
    ) -> Result<TerminalNpoTip5PackedLookupLogupAccumulatorProfile, NativeTerminalVerifyError>
    {
        if trace_profile.padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let field_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let field_columns = Self::terminal_npo_tip5_packed_lookup_logup_groups();
        Ok(TerminalNpoTip5PackedLookupLogupAccumulatorProfile {
            trace: trace_profile.clone(),
            rows: trace_profile.rows,
            padded_rows: trace_profile.padded_rows,
            log_rows: trace_profile.log_rows,
            field_basis_dimension,
            field_columns,
            basis_columns: field_columns * field_basis_dimension,
            proximity: trace_profile.proximity,
        })
    }

    fn terminal_npo_tip5_packed_lookup_logup_quotient_profile(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
    ) -> Result<TerminalNpoTip5PackedLookupLogupQuotientProfile, NativeTerminalVerifyError> {
        if trace_profile.padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let degree = (Self::terminal_npo_tip5_packed_lookup_logup_group_size() + 1)
            .max(trace_profile.max_constraint_degree);
        let padded_rows = trace_profile.padded_rows.checked_mul(degree).ok_or(
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: "terminal packed Tip5 lookup LogUp quotient domain overflow".into(),
            },
        )?;
        Ok(TerminalNpoTip5PackedLookupLogupQuotientProfile {
            trace: trace_profile.clone(),
            rows: trace_profile.rows,
            padded_rows,
            log_rows: padded_rows.trailing_zeros() as usize,
            field_basis_dimension:
                <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            proximity: trace_profile.proximity,
        })
    }

    const fn terminal_npo_tip5_packed_lookup_logup_query_interactions() -> usize {
        TIP5_PERM_ROUNDS * Self::TIP5_LOOKUP_NS * Self::TIP5_LOOKUP_NBYTES
    }

    const fn terminal_npo_tip5_packed_lookup_logup_interactions() -> usize {
        Self::terminal_npo_tip5_packed_lookup_logup_query_interactions() + 1
    }

    const fn terminal_npo_tip5_packed_lookup_logup_group_size() -> usize {
        7
    }

    const fn terminal_npo_tip5_packed_lookup_logup_groups() -> usize {
        let group_size = Self::terminal_npo_tip5_packed_lookup_logup_group_size();
        (Self::terminal_npo_tip5_packed_lookup_logup_interactions() + group_size - 1) / group_size
    }

    fn validate_terminal_npo_tip5_packed_lookup_logup_table_matrix(
        profile: &TerminalNpoTip5PackedLookupLogupTableProfile,
        matrix: &RowMajorMatrix<Goldilocks>,
    ) -> Result<(), NativeTerminalVerifyError> {
        if matrix.width() != profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_table_width".into(),
                    expected: profile.basis_columns,
                    got: matrix.width(),
                },
            );
        }
        if matrix.height() != profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_table_rows".into(),
                    expected: profile.padded_rows,
                    got: matrix.height(),
                },
            );
        }
        Ok(())
    }

    fn terminal_npo_tip5_packed_lookup_logup_table_multiplicity_matrix_goldilocks(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(trace_profile, trace)?;
        if trace_profile.padded_rows < TIP5_LOOKUP_TABLE_ROWS {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_table_domain_rows".into(),
                    expected: TIP5_LOOKUP_TABLE_ROWS,
                    got: trace_profile.padded_rows,
                },
            );
        }
        let mut multiplicities = vec![Goldilocks::ZERO; trace_profile.padded_rows];
        for row in 0..trace_profile.padded_rows {
            for round in 0..TIP5_PERM_ROUNDS {
                for lane in 0..Self::TIP5_LOOKUP_NS {
                    for byte in 0..Self::TIP5_LOOKUP_NBYTES {
                        let b = trace.values
                            [row * trace_profile.main_width
                                + Self::terminal_npo_tip5_packed_lookup_b_col(
                                    round, lane, byte,
                                )]
                        .as_canonical_u64();
                        let c = trace.values
                            [row * trace_profile.main_width
                                + Self::terminal_npo_tip5_packed_lookup_c_col(
                                    round, lane, byte,
                                )]
                        .as_canonical_u64();
                        if b >= TIP5_LOOKUP_TABLE_ROWS as u64 {
                            return Err(
                                NativeTerminalVerifyError::TerminalOracleOpeningValueNonCanonical {
                                    limb: byte,
                                    value: b,
                                },
                            );
                        }
                        let expected_c = TIP5_LOOKUP_TABLE[b as usize] as u64;
                        if c != expected_c {
                            return Err(
                                NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                                    label: "tip5_packed_lookup_logup_table_pair".into(),
                                },
                            );
                        }
                        multiplicities[b as usize] += Goldilocks::ONE;
                    }
                }
            }
        }
        Ok(RowMajorMatrix::new_col(multiplicities))
    }

    fn terminal_npo_tip5_packed_lookup_logup_table_fixed_evals(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
    ) -> Result<[Vec<Goldilocks>; 3], NativeTerminalVerifyError> {
        if trace_profile.padded_rows < TIP5_LOOKUP_TABLE_ROWS {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_fixed_table_rows".into(),
                    expected: TIP5_LOOKUP_TABLE_ROWS,
                    got: trace_profile.padded_rows,
                },
            );
        }
        let mut selector = vec![Goldilocks::ZERO; trace_profile.padded_rows];
        let mut input = vec![Goldilocks::ZERO; trace_profile.padded_rows];
        let mut output = vec![Goldilocks::ZERO; trace_profile.padded_rows];
        for row in 0..TIP5_LOOKUP_TABLE_ROWS {
            selector[row] = Goldilocks::ONE;
            input[row] = Goldilocks::from_u64(row as u64);
            output[row] = Goldilocks::from_u64(TIP5_LOOKUP_TABLE[row] as u64);
        }
        Ok([selector, input, output])
    }

    fn terminal_npo_tip5_packed_lookup_logup_interaction_contribution_goldilocks(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &RowMajorMatrix<Goldilocks>,
        table_matrix: &RowMajorMatrix<Goldilocks>,
        row: usize,
        interaction: usize,
        alpha: TerminalFriChallenge,
        beta: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        if interaction >= Self::terminal_npo_tip5_packed_lookup_logup_interactions() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_interaction".into(),
                    expected: Self::terminal_npo_tip5_packed_lookup_logup_interactions(),
                    got: interaction + 1,
                },
            );
        }
        let combine = |left: Goldilocks, right: Goldilocks| {
            TerminalFriChallenge::from(left) * beta + TerminalFriChallenge::from(right)
        };
        let invert = |denominator: TerminalFriChallenge| {
            denominator.try_inverse().ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal packed Tip5 lookup LogUp challenge hit a denominator pole"
                        .into(),
                }
            })
        };
        if interaction < Self::terminal_npo_tip5_packed_lookup_logup_query_interactions() {
            let byte = interaction % Self::TIP5_LOOKUP_NBYTES;
            let lane =
                (interaction / Self::TIP5_LOOKUP_NBYTES) % Self::TIP5_LOOKUP_NS;
            let round =
                interaction / (Self::TIP5_LOOKUP_NBYTES * Self::TIP5_LOOKUP_NS);
            let base = row * trace_profile.main_width;
            let denominator = alpha
                - combine(
                    trace.values
                        [base + Self::terminal_npo_tip5_packed_lookup_b_col(round, lane, byte)],
                    trace.values
                        [base + Self::terminal_npo_tip5_packed_lookup_c_col(round, lane, byte)],
                );
            Ok(invert(denominator)?)
        } else if row < TIP5_LOOKUP_TABLE_ROWS {
            let tmult = TerminalFriChallenge::from(table_matrix.values[row]);
            if tmult == TerminalFriChallenge::ZERO {
                return Ok(TerminalFriChallenge::ZERO);
            }
            let tin = Goldilocks::from_u64(row as u64);
            let tout = Goldilocks::from_u64(TIP5_LOOKUP_TABLE[row] as u64);
            Ok(-tmult * invert(alpha - combine(tin, tout))?)
        } else {
            Ok(TerminalFriChallenge::ZERO)
        }
    }

    fn terminal_npo_tip5_packed_lookup_logup_accumulator_matrix_goldilocks(
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace: &RowMajorMatrix<Goldilocks>,
        table_matrix: &RowMajorMatrix<Goldilocks>,
        challenges: &[(TerminalFriChallenge, TerminalFriChallenge)],
    ) -> Result<(RowMajorMatrix<Goldilocks>, Vec<TerminalFriChallenge>), NativeTerminalVerifyError>
    {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(trace_profile, trace)?;
        let table_profile =
            Self::terminal_npo_tip5_packed_lookup_logup_table_profile(trace_profile)?;
        Self::validate_terminal_npo_tip5_packed_lookup_logup_table_matrix(
            &table_profile,
            table_matrix,
        )?;
        let interaction_count = Self::terminal_npo_tip5_packed_lookup_logup_interactions();
        let group_count = Self::terminal_npo_tip5_packed_lookup_logup_groups();
        if challenges.len() != interaction_count {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_challenges".into(),
                    expected: interaction_count,
                    got: challenges.len(),
                },
            );
        }

        let basis_dimension = <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let mut values =
            Vec::with_capacity(trace_profile.padded_rows * group_count * basis_dimension);
        let mut running = vec![TerminalFriChallenge::ZERO; group_count];
        for row in 0..trace_profile.padded_rows {
            for value in &running {
                values.extend_from_slice(value.as_basis_coefficients_slice());
            }
            for (group, running_group) in running.iter_mut().enumerate() {
                let start = group * Self::terminal_npo_tip5_packed_lookup_logup_group_size();
                let end = (start + Self::terminal_npo_tip5_packed_lookup_logup_group_size())
                    .min(interaction_count);
                for interaction in start..end {
                    let (alpha, beta) = challenges[interaction];
                    *running_group +=
                        Self::terminal_npo_tip5_packed_lookup_logup_interaction_contribution_goldilocks(
                            trace_profile,
                            trace,
                            table_matrix,
                            row,
                            interaction,
                            alpha,
                            beta,
                        )?;
                }
            }
        }
        let final_sum = running.iter().copied().sum::<TerminalFriChallenge>();
        if final_sum != TerminalFriChallenge::ZERO {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriRelationMismatch {
                    label: "tip5_packed_lookup_logup_accumulator_final".into(),
                },
            );
        }
        Ok((
            RowMajorMatrix::new(values, group_count * basis_dimension),
            running,
        ))
    }

    fn terminal_npo_tip5_packed_lookup_logup_interaction_terms_at_point(
        trace: &[TerminalFriChallenge],
        table_multiplicity: TerminalFriChallenge,
        table_preprocessed: &[TerminalFriChallenge],
        interaction: usize,
        beta: TerminalFriChallenge,
    ) -> Result<(TerminalFriChallenge, TerminalFriChallenge), NativeTerminalVerifyError> {
        if interaction >= Self::terminal_npo_tip5_packed_lookup_logup_interactions() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_opened_interaction".into(),
                    expected: Self::terminal_npo_tip5_packed_lookup_logup_interactions(),
                    got: interaction + 1,
                },
            );
        }
        let combine = |left: TerminalFriChallenge, right: TerminalFriChallenge| left * beta + right;
        if interaction < Self::terminal_npo_tip5_packed_lookup_logup_query_interactions() {
            let byte = interaction % Self::TIP5_LOOKUP_NBYTES;
            let lane =
                (interaction / Self::TIP5_LOOKUP_NBYTES) % Self::TIP5_LOOKUP_NS;
            let round =
                interaction / (Self::TIP5_LOOKUP_NBYTES * Self::TIP5_LOOKUP_NS);
            Ok((
                TerminalFriChallenge::ONE,
                combine(
                    trace[Self::terminal_npo_tip5_packed_lookup_b_col(round, lane, byte)],
                    trace[Self::terminal_npo_tip5_packed_lookup_c_col(round, lane, byte)],
                ),
            ))
        } else {
            if table_preprocessed.len() != 3 {
                return Err(
                    NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                        expected: 3,
                        got: table_preprocessed.len(),
                    },
                );
            }
            Ok((
                -table_preprocessed[0] * table_multiplicity,
                combine(table_preprocessed[1], table_preprocessed[2]),
            ))
        }
    }

    fn terminal_npo_tip5_packed_lookup_logup_group_constraint_at_point(
        trace: &[TerminalFriChallenge],
        table_multiplicity: TerminalFriChallenge,
        accumulator: TerminalFriChallenge,
        next_accumulator: TerminalFriChallenge,
        final_cumulative: TerminalFriChallenge,
        table_preprocessed: &[TerminalFriChallenge],
        challenges: &[(TerminalFriChallenge, TerminalFriChallenge)],
        group: usize,
        first_selector: TerminalFriChallenge,
        last_selector: TerminalFriChallenge,
        transition_selector: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        let interaction_count = Self::terminal_npo_tip5_packed_lookup_logup_interactions();
        if challenges.len() != interaction_count {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_group_challenges".into(),
                    expected: interaction_count,
                    got: challenges.len(),
                },
            );
        }
        if group >= Self::terminal_npo_tip5_packed_lookup_logup_groups() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_group".into(),
                    expected: Self::terminal_npo_tip5_packed_lookup_logup_groups(),
                    got: group + 1,
                },
            );
        }

        let group_size = Self::terminal_npo_tip5_packed_lookup_logup_group_size();
        let start = group * group_size;
        let end = (start + group_size).min(interaction_count);
        let mut denominators = Vec::with_capacity(end - start);
        let mut multiplicities = Vec::with_capacity(end - start);
        for interaction in start..end {
            let (alpha, beta) = challenges[interaction];
            let (multiplicity, combined) =
                Self::terminal_npo_tip5_packed_lookup_logup_interaction_terms_at_point(
                    trace,
                    table_multiplicity,
                    table_preprocessed,
                    interaction,
                    beta,
                )?;
            denominators.push(alpha - combined);
            multiplicities.push(multiplicity);
        }

        let mut denominator_product = TerminalFriChallenge::ONE;
        for denominator in &denominators {
            denominator_product *= *denominator;
        }
        let mut numerator = TerminalFriChallenge::ZERO;
        for term in 0..denominators.len() {
            let mut other_denominators = TerminalFriChallenge::ONE;
            for (other, denominator) in denominators.iter().enumerate() {
                if other != term {
                    other_denominators *= *denominator;
                }
            }
            numerator += multiplicities[term] * other_denominators;
        }

        let transition = (next_accumulator - accumulator) * denominator_product - numerator;
        let final_row = (final_cumulative - accumulator) * denominator_product - numerator;
        Ok(first_selector * accumulator
            + transition_selector * transition
            + last_selector * final_row)
    }

    fn terminal_npo_tip5_packed_lookup_logup_quotient_matrix_goldilocks(
        trace_domain: TerminalFriDomain,
        quotient_domain: TerminalFriDomain,
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
        trace_matrix: &RowMajorMatrix<Goldilocks>,
        table_profile: &TerminalNpoTip5PackedLookupLogupTableProfile,
        table_matrix: &RowMajorMatrix<Goldilocks>,
        accumulator_matrix: &RowMajorMatrix<Goldilocks>,
        final_cumulatives: &[TerminalFriChallenge],
        challenges: &[(TerminalFriChallenge, TerminalFriChallenge)],
        gamma: TerminalFriChallenge,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        Self::validate_terminal_npo_tip5_packed_lookup_trace_matrix(trace_profile, trace_matrix)?;
        Self::validate_terminal_npo_tip5_packed_lookup_logup_table_matrix(
            table_profile,
            table_matrix,
        )?;
        let interaction_count = Self::terminal_npo_tip5_packed_lookup_logup_interactions();
        let group_count = Self::terminal_npo_tip5_packed_lookup_logup_groups();
        let basis_dimension = <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        if challenges.len() != interaction_count {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_quotient_challenges".into(),
                    expected: interaction_count,
                    got: challenges.len(),
                },
            );
        }
        if final_cumulatives.len() != group_count {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_final_cumulatives".into(),
                    expected: group_count,
                    got: final_cumulatives.len(),
                },
            );
        }
        if accumulator_matrix.width() != group_count * basis_dimension {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_quotient_accumulator_width".into(),
                    expected: group_count * basis_dimension,
                    got: accumulator_matrix.width(),
                },
            );
        }
        if accumulator_matrix.height() != trace_profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_quotient_accumulator_rows".into(),
                    expected: trace_profile.padded_rows,
                    got: accumulator_matrix.height(),
                },
            );
        }

        let fixed_evals =
            Self::terminal_npo_tip5_packed_lookup_logup_table_fixed_evals(trace_profile)?;
        let trace_width = trace_profile.main_width;
        let table_width = table_profile.basis_columns;
        let accumulator_width = accumulator_matrix.width();
        let fixed_width = fixed_evals.len();
        let table_offset = trace_width;
        let accumulator_offset = table_offset + table_width;
        let fixed_offset = accumulator_offset + accumulator_width;
        let lde_width = fixed_offset + fixed_width;
        let mut lde_values = Vec::with_capacity(trace_profile.padded_rows * lde_width);
        for row in 0..trace_profile.padded_rows {
            let trace_start = row * trace_width;
            lde_values.extend_from_slice(&trace_matrix.values[trace_start..trace_start + trace_width]);
            lde_values.push(table_matrix.values[row]);
            let accumulator_start = row * accumulator_width;
            lde_values.extend_from_slice(
                &accumulator_matrix.values
                    [accumulator_start..accumulator_start + accumulator_width],
            );
            for evals in &fixed_evals {
                lde_values.push(evals[row]);
            }
        }
        let lde_matrix = Self::terminal_coset_lde_matrix_goldilocks(
            "tip5_packed_lookup_logup_quotient",
            trace_domain,
            quotient_domain,
            RowMajorMatrix::new(lde_values, lde_width),
        )?;
        if lde_matrix.width() != lde_width {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: lde_width,
                    got: lde_matrix.width(),
                },
            );
        }
        let next_row_stride = quotient_domain
            .size()
            .checked_div(trace_domain.size())
            .filter(|ratio| ratio.is_power_of_two())
            .ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_logup_quotient_lde_stride".into(),
                    expected: trace_domain.size() * 2,
                    got: quotient_domain.size(),
                },
            )?;
        let selectors = trace_domain.selectors_on_coset(quotient_domain);
        tracing::info!(
            trace_rows = trace_profile.padded_rows,
            quotient_rows = quotient_domain.size(),
            trace_width,
            table_width,
            accumulator_width,
            fixed_width,
            interactions = interaction_count,
            groups = group_count,
            "terminal packed Tip5 LogUp quotient shape"
        );
        let quotient_values = (0..quotient_domain.size())
            .into_par_iter()
            .map(|row| -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
                let row_base = row * lde_width;
                let next_row = (row + next_row_stride) % quotient_domain.size();
                let next_row_base = next_row * lde_width;
                let opened_trace = (0..trace_width)
                    .map(|column| TerminalFriChallenge::from(lde_matrix.values[row_base + column]))
                    .collect::<Vec<_>>();
                let table_multiplicity =
                    TerminalFriChallenge::from(lde_matrix.values[row_base + table_offset]);
                let table_preprocessed = (0..fixed_width)
                    .map(|column| {
                        TerminalFriChallenge::from(
                            lde_matrix.values[row_base + fixed_offset + column],
                        )
                    })
                    .collect::<Vec<_>>();
                let mut relation = TerminalFriChallenge::ZERO;
                let mut coeff = TerminalFriChallenge::ONE;
                for group in 0..group_count {
                    let offset = group * basis_dimension;
                    let accumulator =
                        <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::from_basis_coefficients_slice(
                            &lde_matrix.values[row_base + accumulator_offset + offset
                                ..row_base + accumulator_offset + offset + basis_dimension],
                        )
                        .ok_or(
                            NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                                expected: basis_dimension,
                                got: accumulator_width,
                            },
                        )?;
                    let next_accumulator =
                        <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::from_basis_coefficients_slice(
                            &lde_matrix.values[next_row_base + accumulator_offset + offset
                                ..next_row_base + accumulator_offset + offset + basis_dimension],
                        )
                        .ok_or(
                            NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                                expected: basis_dimension,
                                got: accumulator_width,
                            },
                        )?;
                    relation += coeff
                        * Self::terminal_npo_tip5_packed_lookup_logup_group_constraint_at_point(
                            &opened_trace,
                            table_multiplicity,
                            accumulator,
                            next_accumulator,
                            final_cumulatives[group],
                            &table_preprocessed,
                            challenges,
                            group,
                            TerminalFriChallenge::from(selectors.is_first_row[row]),
                            TerminalFriChallenge::from(selectors.is_last_row[row]),
                            TerminalFriChallenge::from(selectors.is_transition[row]),
                        )?;
                    coeff *= gamma;
                }
                Ok(relation * TerminalFriChallenge::from(selectors.inv_vanishing[row]))
            })
            .collect::<Result<Vec<_>, _>>()?;
        let quotient = RowMajorMatrix::new_col(quotient_values).flatten_to_base();
        if quotient.width() != basis_dimension {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: basis_dimension,
                    got: quotient.width(),
                },
            );
        }
        Ok(quotient)
    }

    fn terminal_npo_tip5_lookup_npo_rows_io_profile(
        trace_profile: &TerminalNpoTip5LookupTraceProfile,
        layout: &TerminalNpoPolynomialColumnLayout,
    ) -> Result<TerminalNpoTip5LookupNpoRowsIoProfile, NativeTerminalVerifyError> {
        Self::verify_terminal_npo_tip5_lookup_trace_profile_digest(trace_profile)?;
        if layout.rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        if trace_profile.tip5_rows > layout.rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_tip5_rows".into(),
                    expected: layout.rows,
                    got: trace_profile.tip5_rows,
                },
            );
        }
        Ok(TerminalNpoTip5LookupNpoRowsIoProfile {
            trace: trace_profile.clone(),
            rows: layout.rows,
            padded_rows: 1usize << layout.log_rows,
            log_rows: layout.log_rows,
            field_basis_dimension: <Goldilocks as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 26,
            basis_columns: 26,
            proximity: TerminalProximityProfile::production_60bit(),
        })
    }

    fn terminal_npo_tip5_lookup_npo_rows_value_bridge_quotient_profile(
        lookup_io_profile: &TerminalNpoTip5LookupNpoRowsIoProfile,
    ) -> Result<TerminalNpoTip5LookupNpoRowsValueBridgeQuotientProfile, NativeTerminalVerifyError>
    {
        if lookup_io_profile.padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let padded_rows = lookup_io_profile.padded_rows * 2;
        Ok(TerminalNpoTip5LookupNpoRowsValueBridgeQuotientProfile {
            rows: lookup_io_profile.rows,
            padded_rows,
            log_rows: lookup_io_profile.log_rows + 1,
            field_basis_dimension:
                <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            proximity: lookup_io_profile.proximity,
        })
    }

    fn terminal_npo_tip5_lookup_npo_rows_io_matrix_goldilocks<F>(
        trace_profile: &TerminalNpoTip5LookupTraceProfile,
        columns: &TerminalNpoPolynomialColumns<F>,
        trace: &RowMajorMatrix<Goldilocks>,
    ) -> Result<
        (
            TerminalNpoTip5LookupNpoRowsIoProfile,
            RowMajorMatrix<Goldilocks>,
        ),
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        if trace.width() != trace_profile.main_width {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_trace_width".into(),
                    expected: trace_profile.main_width,
                    got: trace.width(),
                },
            );
        }
        if trace.height() != trace_profile.main_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_trace_rows".into(),
                    expected: trace_profile.main_rows,
                    got: trace.height(),
                },
            );
        }
        let profile =
            Self::terminal_npo_tip5_lookup_npo_rows_io_profile(trace_profile, &columns.layout)?;
        let mut values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        let is_tip5_index = Self::terminal_npo_polynomial_column_index(columns, "is_tip5")?;
        let mut tip5_row = 0usize;
        for row in 0..columns.layout.rows {
            let is_tip5 = Self::terminal_npo_polynomial_column_base_value(
                columns,
                is_tip5_index,
                row,
                "is_tip5",
            )?;
            if is_tip5 == Goldilocks::ZERO {
                continue;
            }
            let final_trace_row =
                Self::terminal_npo_tip5_lookup_round_row(tip5_row, TIP5_PERM_ROUNDS - 1);
            if final_trace_row >= profile.trace.main_rows {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                        label: "tip5_lookup_npo_rows_io_trace_row".into(),
                        expected: profile.trace.main_rows,
                        got: final_trace_row,
                    },
                );
            }
            for limb in 0..16 {
                values[row * profile.basis_columns + limb] =
                    trace.values[final_trace_row * trace.width() + Self::TIP5_LOOKUP_C_TIN + limb];
            }
            for limb in 0..10 {
                let present_label = format!("output_present_{limb}");
                let present_index =
                    Self::terminal_npo_polynomial_column_index(columns, &present_label)?;
                let present = Self::terminal_npo_polynomial_column_base_value(
                    columns,
                    present_index,
                    row,
                    &present_label,
                )?;
                if present != Goldilocks::ZERO {
                    let output_offset = Self::terminal_npo_tip5_lookup_terminal_output_offset();
                    values[row * profile.basis_columns + 16 + limb] =
                        trace.values[final_trace_row * trace.width() + output_offset + limb];
                }
            }
            tip5_row += 1;
        }
        if tip5_row != profile.trace.tip5_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_tip5_rows".into(),
                    expected: profile.trace.tip5_rows,
                    got: tip5_row,
                },
            );
        }
        Ok((
            profile.clone(),
            RowMajorMatrix::new(values, profile.basis_columns),
        ))
    }

    fn terminal_npo_tip5_lookup_npo_rows_io_matrix_from_values_goldilocks<F>(
        trace_profile: &TerminalNpoTip5LookupTraceProfile,
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<
        (
            TerminalNpoTip5LookupNpoRowsIoProfile,
            RowMajorMatrix<Goldilocks>,
        ),
        NativeTerminalVerifyError,
    >
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        let profile =
            Self::terminal_npo_tip5_lookup_npo_rows_io_profile(trace_profile, &columns.layout)?;
        let mut values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        let is_tip5_index = Self::terminal_npo_polynomial_column_index(columns, "is_tip5")?;
        let mut tip5_row = 0usize;
        for row in 0..columns.layout.rows {
            let is_tip5 = Self::terminal_npo_polynomial_column_base_value(
                columns,
                is_tip5_index,
                row,
                "is_tip5",
            )?;
            if is_tip5 == Goldilocks::ZERO {
                continue;
            }
            for limb in 0..16 {
                values[row * profile.basis_columns + limb] =
                    Self::terminal_npo_polynomial_tip5_input_lane_base_value(
                        columns, row, limb,
                    )?;
            }
            for limb in 0..10 {
                let present_label = format!("output_present_{limb}");
                let present_index =
                    Self::terminal_npo_polynomial_column_index(columns, &present_label)?;
                let present = Self::terminal_npo_polynomial_column_base_value(
                    columns,
                    present_index,
                    row,
                    &present_label,
                )?;
                if present != Goldilocks::ZERO {
                    let output_label = format!("output_value_{limb}");
                    let output_index =
                        Self::terminal_npo_polynomial_column_index(columns, &output_label)?;
                    values[row * profile.basis_columns + 16 + limb] =
                        Self::terminal_npo_polynomial_column_base_value(
                            columns,
                            output_index,
                            row,
                            &output_label,
                        )?;
                }
            }
            tip5_row += 1;
        }
        if tip5_row != profile.trace.tip5_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_npo_rows_io_values_tip5_rows".into(),
                    expected: profile.trace.tip5_rows,
                    got: tip5_row,
                },
            );
        }
        Ok((
            profile.clone(),
            RowMajorMatrix::new(values, profile.basis_columns),
        ))
    }

    fn terminal_npo_polynomial_tip5_row_indices<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<Vec<usize>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        let is_tip5_index = Self::terminal_npo_polynomial_column_index(columns, "is_tip5")?;
        let mut rows = Vec::new();
        for row in 0..columns.layout.rows {
            let is_tip5 = Self::terminal_npo_polynomial_column_base_value(
                columns,
                is_tip5_index,
                row,
                "is_tip5",
            )?;
            if is_tip5 != Goldilocks::ZERO {
                rows.push(row);
            }
        }
        Ok(rows)
    }

    const fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lanes() -> usize {
        26
    }

    const fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_group_size() -> usize {
        3
    }

    const fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_groups() -> usize {
        let lanes = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lanes();
        let group_size = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_group_size();
        (lanes + group_size - 1) / group_size
    }

    fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_accumulator_profile(
        rows: usize,
        padded_rows: usize,
        proximity: TerminalProximityProfile,
    ) -> Result<
        TerminalNpoTip5LookupTraceDomainNpoIoLogupAccumulatorProfile,
        NativeTerminalVerifyError,
    > {
        if rows == 0 || padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let field_basis_dimension =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let field_columns = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_groups();
        Ok(
            TerminalNpoTip5LookupTraceDomainNpoIoLogupAccumulatorProfile {
                rows,
                padded_rows,
                log_rows: padded_rows.trailing_zeros() as usize,
                field_basis_dimension,
                field_columns,
                basis_columns: field_columns * field_basis_dimension,
                proximity,
            },
        )
    }

    fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_quotient_profile(
        rows: usize,
        padded_rows: usize,
        proximity: TerminalProximityProfile,
    ) -> Result<TerminalNpoTip5LookupTraceDomainNpoIoLogupQuotientProfile, NativeTerminalVerifyError>
    {
        if rows == 0 || padded_rows == 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryDomainEmpty);
        }
        let degree = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_group_size() + 1;
        let quotient_rows = padded_rows.checked_mul(degree).ok_or(
            NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                reason: "terminal Tip5 trace-domain NPO IO LogUp quotient domain overflow".into(),
            },
        )?;
        Ok(TerminalNpoTip5LookupTraceDomainNpoIoLogupQuotientProfile {
            rows,
            padded_rows: quotient_rows,
            log_rows: quotient_rows.trailing_zeros() as usize,
            field_basis_dimension:
                <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            field_columns: 1,
            basis_columns: <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION,
            proximity,
        })
    }

    fn terminal_npo_tip5_lookup_selected_row_selector_rank_evals<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<(Vec<Goldilocks>, Vec<Goldilocks>), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let rows = Self::terminal_npo_polynomial_tip5_row_indices(columns)?;
        let padded_rows = 1usize << columns.layout.log_rows;
        let mut selector = vec![Goldilocks::ZERO; padded_rows];
        let mut rank = vec![Goldilocks::ZERO; padded_rows];
        for (tip5_rank, row) in rows.iter().copied().enumerate() {
            selector[row] = Goldilocks::ONE;
            rank[row] = Goldilocks::from_u64(tip5_rank as u64);
        }
        Ok((selector, rank))
    }

    fn terminal_npo_tip5_lookup_trace_row_selector_rank_evals(
        trace_profile: &TerminalNpoTip5LookupTraceProfile,
    ) -> Result<(Vec<Goldilocks>, Vec<Goldilocks>), NativeTerminalVerifyError> {
        Self::verify_terminal_npo_tip5_lookup_trace_profile_digest(trace_profile)?;
        let padded_rows = trace_profile.main_rows.next_power_of_two();
        let mut selector = vec![Goldilocks::ZERO; padded_rows];
        let mut rank = vec![Goldilocks::ZERO; padded_rows];
        for tip5_rank in 0..trace_profile.tip5_rows {
            let row = Self::terminal_npo_tip5_lookup_round_row(tip5_rank, TIP5_PERM_ROUNDS - 1);
            if row >= padded_rows {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                        label: "tip5_lookup_trace_domain_npo_io_logup_trace_rank_row".into(),
                        expected: padded_rows,
                        got: row + 1,
                    },
                );
            }
            selector[row] = Goldilocks::ONE;
            rank[row] = Goldilocks::from_u64(tip5_rank as u64);
        }
        Ok((selector, rank))
    }

    fn terminal_npo_tip5_lookup_selected_npo_io_lane_selector_rank_evals<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<(RowMajorMatrix<Goldilocks>, Vec<Goldilocks>), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let lanes = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lanes();
        let rows = Self::terminal_npo_polynomial_tip5_row_indices(columns)?;
        let padded_rows = 1usize << columns.layout.log_rows;
        let mut lane_selectors = vec![Goldilocks::ZERO; padded_rows * lanes];
        let mut rank = vec![Goldilocks::ZERO; padded_rows];
        for (tip5_rank, row) in rows.iter().copied().enumerate() {
            for limb in 0..16 {
                lane_selectors[row * lanes + limb] = Goldilocks::ONE;
            }
            for limb in 0..10 {
                let present_label = format!("output_present_{limb}");
                let present_index =
                    Self::terminal_npo_polynomial_column_index(columns, &present_label)?;
                lane_selectors[row * lanes + 16 + limb] =
                    Self::terminal_npo_polynomial_column_base_value(
                        columns,
                        present_index,
                        row,
                        &present_label,
                    )?;
            }
            rank[row] = Goldilocks::from_u64(tip5_rank as u64);
        }
        Ok((RowMajorMatrix::new(lane_selectors, lanes), rank))
    }

    fn terminal_npo_tip5_packed_lookup_npo_io_lane_selector_rank_evals<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        trace_profile: &TerminalNpoTip5PackedLookupTraceProfile,
    ) -> Result<(RowMajorMatrix<Goldilocks>, Vec<Goldilocks>), NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        if trace_profile.tip5_rows > trace_profile.padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_npo_io_lane_selector_rows".into(),
                    expected: trace_profile.padded_rows,
                    got: trace_profile.tip5_rows,
                },
            );
        }
        let tip5_rows = Self::terminal_npo_polynomial_tip5_row_indices(columns)?;
        if tip5_rows.len() != trace_profile.tip5_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_packed_lookup_npo_io_lane_selector_tip5_rows".into(),
                    expected: trace_profile.tip5_rows,
                    got: tip5_rows.len(),
                },
            );
        }
        let lanes = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lanes();
        let mut lane_selectors = vec![Goldilocks::ZERO; trace_profile.padded_rows * lanes];
        let mut rank = vec![Goldilocks::ZERO; trace_profile.padded_rows];
        for (tip5_rank, npo_row) in tip5_rows.iter().copied().enumerate() {
            for limb in 0..16 {
                lane_selectors[tip5_rank * lanes + limb] = Goldilocks::ONE;
            }
            for limb in 0..10 {
                let present_label = format!("output_present_{limb}");
                let present_index =
                    Self::terminal_npo_polynomial_column_index(columns, &present_label)?;
                lane_selectors[tip5_rank * lanes + 16 + limb] =
                    Self::terminal_npo_polynomial_column_base_value(
                        columns,
                        present_index,
                        npo_row,
                        &present_label,
                    )?;
            }
            rank[tip5_rank] = Goldilocks::from_u64(tip5_rank as u64);
        }
        Ok((RowMajorMatrix::new(lane_selectors, lanes), rank))
    }

    fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_accumulator_matrix_goldilocks(
        value_matrix: &RowMajorMatrix<Goldilocks>,
        value_offset: usize,
        rows: usize,
        padded_rows: usize,
        selector_evals: &[Goldilocks],
        rank_evals: &[Goldilocks],
        sign: TerminalFriChallenge,
        alpha: TerminalFriChallenge,
        beta_rank: TerminalFriChallenge,
        beta_limb: TerminalFriChallenge,
    ) -> Result<(RowMajorMatrix<Goldilocks>, Vec<TerminalFriChallenge>), NativeTerminalVerifyError>
    {
        let lanes = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lanes();
        if value_offset + lanes > value_matrix.width() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_value_width".into(),
                    expected: value_offset + lanes,
                    got: value_matrix.width(),
                },
            );
        }
        if value_matrix.height() != padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_value_rows".into(),
                    expected: padded_rows,
                    got: value_matrix.height(),
                },
            );
        }
        if selector_evals.len() != padded_rows || rank_evals.len() != padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_fixed_rows".into(),
                    expected: padded_rows,
                    got: selector_evals.len().min(rank_evals.len()),
                },
            );
        }
        if rows > padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_rows".into(),
                    expected: padded_rows,
                    got: rows,
                },
            );
        }

        let group_count = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_groups();
        let group_size = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_group_size();
        let basis_dimension = <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let mut values = Vec::with_capacity(padded_rows * group_count * basis_dimension);
        let mut running = vec![TerminalFriChallenge::ZERO; group_count];
        for row in 0..padded_rows {
            for value in &running {
                values.extend_from_slice(value.as_basis_coefficients_slice());
            }
            let selector = TerminalFriChallenge::from(selector_evals[row]);
            if selector == TerminalFriChallenge::ZERO {
                continue;
            }
            let rank = TerminalFriChallenge::from(rank_evals[row]);
            for (group, running_group) in running.iter_mut().enumerate() {
                let start = group * group_size;
                let end = (start + group_size).min(lanes);
                for limb in start..end {
                    let value = TerminalFriChallenge::from(
                        value_matrix.values[row * value_matrix.width() + value_offset + limb],
                    );
                    let limb_challenge =
                        TerminalFriChallenge::from(Goldilocks::from_u64(limb as u64));
                    let combined = rank * beta_rank + limb_challenge * beta_limb + value;
                    let denominator = alpha - combined;
                    let inverse = denominator.try_inverse().ok_or_else(|| {
                        NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                            reason: "terminal Tip5 trace-domain NPO IO LogUp challenge hit a denominator pole".into(),
                        }
                    })?;
                    *running_group += sign * selector * inverse;
                }
            }
        }
        Ok((
            RowMajorMatrix::new(values, group_count * basis_dimension),
            running,
        ))
    }

    fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lane_accumulator_matrix_goldilocks(
        value_matrix: &RowMajorMatrix<Goldilocks>,
        value_offset: usize,
        rows: usize,
        padded_rows: usize,
        lane_selector_evals: &RowMajorMatrix<Goldilocks>,
        rank_evals: &[Goldilocks],
        sign: TerminalFriChallenge,
        alpha: TerminalFriChallenge,
        beta_rank: TerminalFriChallenge,
        beta_limb: TerminalFriChallenge,
    ) -> Result<(RowMajorMatrix<Goldilocks>, Vec<TerminalFriChallenge>), NativeTerminalVerifyError>
    {
        let lanes = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lanes();
        if value_offset + lanes > value_matrix.width() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_lane_value_width".into(),
                    expected: value_offset + lanes,
                    got: value_matrix.width(),
                },
            );
        }
        if value_matrix.height() != padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_lane_value_rows".into(),
                    expected: padded_rows,
                    got: value_matrix.height(),
                },
            );
        }
        if lane_selector_evals.height() != padded_rows
            || lane_selector_evals.width() != lanes
            || rank_evals.len() != padded_rows
        {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_lane_fixed_rows".into(),
                    expected: padded_rows,
                    got: lane_selector_evals.height().min(rank_evals.len()),
                },
            );
        }
        if rows > padded_rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_lane_rows".into(),
                    expected: padded_rows,
                    got: rows,
                },
            );
        }

        let group_count = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_groups();
        let group_size = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_group_size();
        let basis_dimension = <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        let mut values = Vec::with_capacity(padded_rows * group_count * basis_dimension);
        let mut running = vec![TerminalFriChallenge::ZERO; group_count];
        for row in 0..padded_rows {
            for value in &running {
                values.extend_from_slice(value.as_basis_coefficients_slice());
            }
            let rank = TerminalFriChallenge::from(rank_evals[row]);
            for (group, running_group) in running.iter_mut().enumerate() {
                let start = group * group_size;
                let end = (start + group_size).min(lanes);
                for limb in start..end {
                    let lane_selector = TerminalFriChallenge::from(
                        lane_selector_evals.values[row * lanes + limb],
                    );
                    if lane_selector == TerminalFriChallenge::ZERO {
                        continue;
                    }
                    let value = TerminalFriChallenge::from(
                        value_matrix.values[row * value_matrix.width() + value_offset + limb],
                    );
                    let limb_challenge =
                        TerminalFriChallenge::from(Goldilocks::from_u64(limb as u64));
                    let combined = rank * beta_rank + limb_challenge * beta_limb + value;
                    let denominator = alpha - combined;
                    let inverse = denominator.try_inverse().ok_or_else(|| {
                        NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                            reason: "terminal Tip5 trace-domain NPO IO LogUp lane challenge hit a denominator pole".into(),
                        }
                    })?;
                    *running_group += sign * lane_selector * inverse;
                }
            }
        }
        Ok((
            RowMajorMatrix::new(values, group_count * basis_dimension),
            running,
        ))
    }

    fn terminal_npo_tip5_lookup_trace_domain_npo_io_logup_group_constraint_at_point(
        values: &[TerminalFriChallenge],
        value_offset: usize,
        accumulator: TerminalFriChallenge,
        next_accumulator: TerminalFriChallenge,
        final_cumulative: TerminalFriChallenge,
        selector: TerminalFriChallenge,
        rank: TerminalFriChallenge,
        sign: TerminalFriChallenge,
        alpha: TerminalFriChallenge,
        beta_rank: TerminalFriChallenge,
        beta_limb: TerminalFriChallenge,
        group: usize,
        first_selector: TerminalFriChallenge,
        last_selector: TerminalFriChallenge,
        transition_selector: TerminalFriChallenge,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        let lanes = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_lanes();
        let group_size = Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_group_size();
        if group >= Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_groups() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "tip5_lookup_trace_domain_npo_io_logup_group".into(),
                    expected: Self::terminal_npo_tip5_lookup_trace_domain_npo_io_logup_groups(),
                    got: group + 1,
                },
            );
        }
        if value_offset + lanes > values.len() {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: value_offset + lanes,
                    got: values.len(),
                },
            );
        }
        let start = group * group_size;
        let end = (start + group_size).min(lanes);
        let mut denominators = Vec::with_capacity(end - start);
        for limb in start..end {
            let limb_challenge = TerminalFriChallenge::from(Goldilocks::from_u64(limb as u64));
            let combined =
                rank * beta_rank + limb_challenge * beta_limb + values[value_offset + limb];
            denominators.push(alpha - combined);
        }

        let mut denominator_product = TerminalFriChallenge::ONE;
        for denominator in &denominators {
            denominator_product *= *denominator;
        }
        let mut numerator = TerminalFriChallenge::ZERO;
        for term in 0..denominators.len() {
            let mut other_denominators = TerminalFriChallenge::ONE;
            for (other, denominator) in denominators.iter().enumerate() {
                if other != term {
                    other_denominators *= *denominator;
                }
            }
            numerator += sign * selector * other_denominators;
        }

        let transition = (next_accumulator - accumulator) * denominator_product - numerator;
        let final_row = (final_cumulative - accumulator) * denominator_product - numerator;
        Ok(first_selector * accumulator
            + transition_selector * transition
            + last_selector * final_row)
    }

