    fn terminal_fri_matrix_commitment_digest(
        proximity: TerminalProximityProfile,
        padded_rows: usize,
        matrix: RowMajorMatrix<Goldilocks>,
    ) -> Result<TerminalCommitmentDigest, NativeTerminalVerifyError> {
        let (pcs, _) = Self::terminal_fri_pcs_and_challenger(proximity)?;
        let domain =
            <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::natural_domain_for_degree(
                &pcs,
                padded_rows,
            );
        let (commitment, _) = <TerminalFriPcs as Pcs<
            TerminalFriChallenge,
            TerminalFriChallenger,
        >>::commit(&pcs, [(domain, matrix)]);
        Self::terminal_fri_commitment_digest(&commitment)
    }

    fn terminal_row_major_matrix_horizontal_concat_goldilocks(
        label: &str,
        left: &RowMajorMatrix<Goldilocks>,
        right: &RowMajorMatrix<Goldilocks>,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        if left.height() != right.height() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: format!("{label}_rows"),
                    expected: left.height(),
                    got: right.height(),
                },
            );
        }
        let width = left.width() + right.width();
        let mut values = Vec::with_capacity(left.height() * width);
        for row in 0..left.height() {
            let left_start = row * left.width();
            values.extend_from_slice(&left.values[left_start..left_start + left.width()]);
            let right_start = row * right.width();
            values.extend_from_slice(&right.values[right_start..right_start + right.width()]);
        }
        Ok(RowMajorMatrix::new(values, width))
    }

    fn terminal_coset_lde_matrix_goldilocks(
        label: &str,
        domain: TerminalFriDomain,
        quotient_domain: TerminalFriDomain,
        matrix: RowMajorMatrix<Goldilocks>,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        if matrix.height() != domain.size() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: format!("{label}_rows"),
                    expected: domain.size(),
                    got: matrix.height(),
                },
            );
        }
        let added_bits = quotient_domain
            .size()
            .checked_div(domain.size())
            .filter(|ratio| ratio.is_power_of_two())
            .map(|ratio| ratio.trailing_zeros() as usize)
            .ok_or(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: format!("{label}_lde"),
                    expected: domain.size() * 2,
                    got: quotient_domain.size(),
                },
            )?;
        let shift = quotient_domain.first_point() / domain.first_point();
        let lde = TerminalFriDft::default()
            .coset_lde_batch(matrix, added_bits, shift)
            .to_row_major_matrix();
        if lde.height() != quotient_domain.size() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: format!("{label}_lde_shape"),
                    expected: quotient_domain.size(),
                    got: lde.height(),
                },
            );
        }
        Ok(lde)
    }

