    fn terminal_compact_composition_matrix_from_goldilocks_values(
        values: &[Goldilocks],
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError> {
        if values.len() != profile.rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_values".into(),
                    expected: profile.rows,
                    got: values.len(),
                },
            );
        }
        let expected_basis_columns =
            <TerminalFriChallenge as BasedVectorSpace<Goldilocks>>::DIMENSION;
        if profile.basis_columns != expected_basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_basis_columns".into(),
                    expected: expected_basis_columns,
                    got: profile.basis_columns,
                },
            );
        }
        let mut matrix_values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        for (row, value) in values.iter().copied().enumerate() {
            matrix_values[row * profile.basis_columns] = value;
        }
        Ok(RowMajorMatrix::new(matrix_values, profile.basis_columns))
    }

    fn terminal_compact_composition_matrix_from_field_values<F>(
        values: &[F],
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<RowMajorMatrix<Goldilocks>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        if values.len() != profile.rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_values".into(),
                    expected: profile.rows,
                    got: values.len(),
                },
            );
        }
        let mut matrix_values = vec![Goldilocks::ZERO; profile.padded_rows * profile.basis_columns];
        for (row, value) in values.iter().enumerate() {
            let basis = value.as_basis_coefficients_slice();
            if basis.len() > profile.basis_columns {
                return Err(
                    NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                        expected: profile.basis_columns,
                        got: basis.len(),
                    },
                );
            }
            for (basis_index, basis_value) in basis.iter().copied().enumerate() {
                matrix_values[row * profile.basis_columns + basis_index] = basis_value;
            }
        }
        Ok(RowMajorMatrix::new(matrix_values, profile.basis_columns))
    }

    fn terminal_compact_composition_point_values_from_field<F>(
        value: F,
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<Vec<TerminalFriChallenge>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let basis = value.as_basis_coefficients_slice();
        if basis.len() > profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: profile.basis_columns,
                    got: basis.len(),
                },
            );
        }
        Ok((0..profile.basis_columns)
            .map(|basis_index| {
                TerminalFriChallenge::from(
                    basis.get(basis_index).copied().unwrap_or(Goldilocks::ZERO),
                )
            })
            .collect())
    }

    fn terminal_compact_composition_point_values_from_basis(
        basis: &[Vec<u64>],
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<Vec<TerminalFriChallenge>, NativeTerminalVerifyError> {
        if basis.len() != profile.basis_columns {
            return Err(
                NativeTerminalVerifyError::TerminalOracleOpeningValueDimensionMismatch {
                    expected: profile.basis_columns,
                    got: basis.len(),
                },
            );
        }
        basis
            .iter()
            .map(|value_basis| {
                Self::field_from_goldilocks_basis_u64::<TerminalFriChallenge>(value_basis)
            })
            .collect()
    }

    fn terminal_compact_composition_row_point(
        domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        row: usize,
        profile: &TerminalCompactCompositionFriProfile,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        if row >= profile.rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "terminal_compact_composition_row_point".into(),
                    expected: profile.rows,
                    got: row + 1,
                },
            );
        }
        let mut point = TerminalFriChallenge::from(domain.first_point());
        for _ in 0..row {
            point = domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: "terminal compact composition row point outside domain".into(),
                }
            })?;
        }
        Ok(point)
    }

    fn terminal_fri_domain_row_point(
        domain: <TerminalFriPcs as Pcs<TerminalFriChallenge, TerminalFriChallenger>>::Domain,
        row: usize,
        rows: usize,
        label: &'static str,
    ) -> Result<TerminalFriChallenge, NativeTerminalVerifyError> {
        if row >= rows {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: label.into(),
                    expected: rows,
                    got: row + 1,
                },
            );
        }
        let mut point = TerminalFriChallenge::from(domain.first_point());
        for _ in 0..row {
            point = domain.next_point(point).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: format!("{label} outside domain"),
                }
            })?;
        }
        Ok(point)
    }

