    fn terminal_npo_polynomial_combined_column_values<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        challenge: F,
    ) -> Result<Vec<F>, NativeTerminalVerifyError>
    where
        F: Field,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        let mut combined = vec![F::ZERO; columns.layout.rows];
        let mut coeff = F::ONE;
        for column in &columns.columns {
            for (acc, value) in combined.iter_mut().zip(column) {
                *acc += *value * coeff;
            }
            coeff *= challenge;
        }
        Ok(combined)
    }

    fn terminal_npo_polynomial_residual_value_column_indices<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Vec<usize> {
        columns
            .labels
            .iter()
            .enumerate()
            .filter_map(|(index, label)| {
                Self::terminal_npo_polynomial_label_is_residual_value(label).then_some(index)
            })
            .collect()
    }

    pub fn terminal_npo_polynomial_prover_dependent_column_indices<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Vec<usize> {
        columns
            .labels
            .iter()
            .enumerate()
            .filter_map(|(index, label)| {
                (!Self::terminal_npo_polynomial_label_is_verifier_derived(label)).then_some(index)
            })
            .collect()
    }

    fn terminal_npo_polynomial_label_is_witness_value(label: &str) -> bool {
        label.starts_with("input_value_")
            || label.starts_with("output_value_")
            || label.starts_with("hidden_tip5_value_")
            || label == "mmcs_bit"
    }

    fn terminal_npo_polynomial_hidden_tip5_limb(label: &str) -> Option<usize> {
        label
            .strip_prefix("hidden_tip5_value_")
            .and_then(|limb| limb.parse::<usize>().ok())
    }

    fn terminal_npo_polynomial_label_is_residual_value(label: &str) -> bool {
        label.starts_with("residual_value_")
    }

    fn terminal_npo_polynomial_label_is_verifier_derived(label: &str) -> bool {
        !Self::terminal_npo_polynomial_label_is_witness_value(label)
            && !Self::terminal_npo_polynomial_label_is_residual_value(label)
    }

    fn terminal_npo_polynomial_combined_residual_values<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        challenge: F,
    ) -> Result<Vec<F>, NativeTerminalVerifyError>
    where
        F: Field,
    {
        Self::validate_terminal_npo_polynomial_columns(&columns.layout, columns)?;
        let residual_column_indices =
            Self::terminal_npo_polynomial_residual_value_column_indices(columns);
        if residual_column_indices.len() != columns.layout.residual_value_columns {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_residual_value_columns".into(),
                    expected: columns.layout.residual_value_columns,
                    got: residual_column_indices.len(),
                },
            );
        }
        let mut combined = vec![F::ZERO; columns.layout.rows];
        let mut coeff = F::ONE;
        for column_index in residual_column_indices {
            for (acc, value) in combined.iter_mut().zip(&columns.columns[column_index]) {
                *acc += *value * coeff;
            }
            coeff *= challenge;
        }
        Ok(combined)
    }

    fn validate_terminal_npo_polynomial_column_commitments<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        prelude: &TerminalProofPrelude,
        commitments: &[TerminalOracleCommitment],
    ) -> Result<TerminalNpoPolynomialColumnLayout, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let layout = Self::terminal_npo_polynomial_column_layout::<F>(verifying_key);
        let labels = Self::terminal_npo_polynomial_column_labels(&layout);
        if commitments.len() != labels.len() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_column_commitments".into(),
                    expected: labels.len(),
                    got: commitments.len(),
                },
            );
        }
        Self::verify_npo_polynomial_column_prelude_commitments(prelude, commitments)?;
        for (label, commitment) in labels.iter().zip(commitments) {
            let expected_label = Self::terminal_npo_polynomial_column_oracle_label(label);
            if commitment.label != expected_label {
                return Err(
                    NativeTerminalVerifyError::TerminalOracleCommitmentLabelMismatch {
                        expected: expected_label,
                        got: commitment.label.clone(),
                    },
                );
            }
            if commitment.values_len != layout.rows {
                return Err(
                    NativeTerminalVerifyError::TerminalOracleCommitmentLengthMismatch {
                        label: commitment.label.clone(),
                        expected: layout.rows,
                        got: commitment.values_len,
                    },
                );
            }
            Self::verify_prelude_binds_commitment(prelude, commitment)?;
        }
        Ok(layout)
    }

    fn validate_terminal_npo_polynomial_selected_column_commitments<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        prelude: &TerminalProofPrelude,
        column_indices: &[usize],
        commitments: &[TerminalOracleCommitment],
    ) -> Result<TerminalNpoPolynomialColumnLayout, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let layout = Self::terminal_npo_polynomial_column_layout::<F>(verifying_key);
        let labels = Self::terminal_npo_polynomial_column_labels(&layout);
        let expected_indices = labels
            .iter()
            .enumerate()
            .filter_map(|(index, label)| {
                (!Self::terminal_npo_polynomial_label_is_verifier_derived(label)).then_some(index)
            })
            .collect::<Vec<_>>();
        if column_indices != expected_indices.as_slice() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_selected_column_indices".into(),
                    expected: expected_indices.len(),
                    got: column_indices.len(),
                },
            );
        }
        if commitments.len() != column_indices.len() {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_selected_column_commitments".into(),
                    expected: column_indices.len(),
                    got: commitments.len(),
                },
            );
        }
        Self::verify_npo_polynomial_column_prelude_commitments(prelude, commitments)?;
        for (index, commitment) in column_indices.iter().zip(commitments) {
            let label = labels.get(*index).ok_or_else(|| {
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "npo_polynomial_selected_column_index".into(),
                    expected: labels.len(),
                    got: index + 1,
                }
            })?;
            let expected_label = Self::terminal_npo_polynomial_column_oracle_label(label);
            if commitment.label != expected_label {
                return Err(
                    NativeTerminalVerifyError::TerminalOracleCommitmentLabelMismatch {
                        expected: expected_label,
                        got: commitment.label.clone(),
                    },
                );
            }
            if commitment.values_len != layout.rows {
                return Err(
                    NativeTerminalVerifyError::TerminalOracleCommitmentLengthMismatch {
                        label: commitment.label.clone(),
                        expected: layout.rows,
                        got: commitment.values_len,
                    },
                );
            }
            Self::verify_prelude_binds_commitment(prelude, commitment)?;
        }
        Ok(layout)
    }

    fn verify_npo_polynomial_column_prelude_commitments(
        prelude: &TerminalProofPrelude,
        commitments: &[TerminalOracleCommitment],
    ) -> Result<(), NativeTerminalVerifyError> {
        if prelude.commitments.len() != commitments.len() {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentCountMismatch {
                    expected: commitments.len(),
                    got: prelude.commitments.len(),
                },
            );
        }
        for (index, (got, commitment)) in prelude.commitments.iter().zip(commitments).enumerate() {
            if *got != commitment.root {
                return Err(
                    NativeTerminalVerifyError::TerminalPreludeCommitmentMismatch {
                        index,
                        expected: commitment.root,
                        got: *got,
                    },
                );
            }
        }
        Ok(())
    }

    fn evaluate_terminal_npo_polynomial_column_row_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        columns: &TerminalNpoPolynomialColumns<F>,
        npo_index: usize,
        previous_normal_tip5_output: &mut Option<[Goldilocks; 16]>,
        previous_merkle_tip5_output: &mut Option<[Goldilocks; 16]>,
    ) -> Result<TerminalNpoRowEvaluation, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks> + From<Goldilocks>,
    {
        let row_ref = Self::terminal_npo_row(verifying_key, npo_index).ok_or(
            NativeTerminalVerifyError::TerminalNpoQueryIndexMismatch {
                query: 0,
                expected: npo_index,
                got: npo_index,
            },
        )?;
        match row_ref {
            NativeTerminalNpoRowRef::Tip5 { row, callsite, .. } => {
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns, "is_tip5", npo_index, true,
                )?;
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "is_recompose",
                    npo_index,
                    false,
                )?;
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "is_recompose_coeff",
                    npo_index,
                    false,
                )?;
                let mode = callsite.tip5_mode.ok_or(
                    NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                        op_type: Self::tip5_op_type().as_str().into(),
                        row,
                        field: "tip5_mode",
                        limb: 0,
                        expected: Some(1),
                        got: None,
                    },
                )?;
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "mode_new_start",
                    npo_index,
                    mode.new_start,
                )?;
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "mode_merkle_path",
                    npo_index,
                    mode.merkle_path,
                )?;
                let (expected_witness_ids, opened_values) =
                    Self::terminal_npo_polynomial_column_opened_values(
                        columns, npo_index, callsite,
                    )?;
                let hidden_inputs = Self::terminal_npo_polynomial_column_hidden_tip5_inputs(
                    columns, npo_index, row, callsite,
                )?;
                self.evaluate_exhaustive_tip5_npo_row_values::<F>(
                    npo_index,
                    row,
                    callsite,
                    &hidden_inputs,
                    &expected_witness_ids,
                    &opened_values,
                    previous_normal_tip5_output,
                    previous_merkle_tip5_output,
                )
            }
            NativeTerminalNpoRowRef::Recompose {
                op_type,
                row,
                callsite,
            } => {
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns, "is_tip5", npo_index, false,
                )?;
                let is_standard = op_type == NpoTypeId::recompose().as_str();
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "is_recompose",
                    npo_index,
                    is_standard,
                )?;
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "is_recompose_coeff",
                    npo_index,
                    !is_standard,
                )?;
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "mode_new_start",
                    npo_index,
                    false,
                )?;
                Self::expect_terminal_npo_polynomial_bool_column(
                    columns,
                    "mode_merkle_path",
                    npo_index,
                    false,
                )?;
                Self::expect_terminal_npo_polynomial_no_hidden_tip5_columns(columns, npo_index)?;
                let (expected_witness_ids, opened_values) =
                    Self::terminal_npo_polynomial_column_opened_values(
                        columns, npo_index, callsite,
                    )?;
                self.evaluate_sampled_recompose_npo_row_values::<F>(
                    npo_index,
                    op_type,
                    row,
                    callsite,
                    &[],
                    &expected_witness_ids,
                    &opened_values,
                )
            }
        }
    }

    fn terminal_npo_polynomial_column_opened_values<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        npo_index: usize,
        callsite: &NativeTerminalNpoCallsite,
    ) -> Result<(Vec<WitnessId>, Vec<F>), NativeTerminalVerifyError>
    where
        F: Field,
    {
        let mut pairs = Vec::<(WitnessId, F)>::new();
        for limb in 0..columns.layout.input_value_columns {
            let witness_id = callsite.inputs.get(limb).copied().flatten();
            let label = format!("input_present_{limb}");
            let expected = witness_id.is_some();
            Self::expect_terminal_npo_polynomial_bool_column(columns, &label, npo_index, expected)?;
            let value_label = format!("input_value_{limb}");
            let value =
                Self::terminal_npo_polynomial_column_value(columns, &value_label, npo_index)?;
            if let Some(witness_id) = witness_id {
                Self::push_terminal_npo_polynomial_opened_value(
                    npo_index, &mut pairs, witness_id, value,
                )?;
            } else if value != F::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: value_label,
                        row: npo_index,
                    },
                );
            }
        }
        for limb in 0..columns.layout.output_value_columns {
            let witness_id = callsite.outputs.get(limb).copied().flatten();
            let label = format!("output_present_{limb}");
            let expected = witness_id.is_some();
            Self::expect_terminal_npo_polynomial_bool_column(columns, &label, npo_index, expected)?;
            let value_label = format!("output_value_{limb}");
            let value =
                Self::terminal_npo_polynomial_column_value(columns, &value_label, npo_index)?;
            if let Some(witness_id) = witness_id {
                Self::push_terminal_npo_polynomial_opened_value(
                    npo_index, &mut pairs, witness_id, value,
                )?;
            } else if value != F::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: value_label,
                        row: npo_index,
                    },
                );
            }
        }
        let mmcs_value =
            Self::terminal_npo_polynomial_column_value(columns, "mmcs_bit", npo_index)?;
        if let Some(witness_id) = callsite.tip5_mmcs_bit {
            Self::expect_terminal_npo_polynomial_bool_column(
                columns,
                "mmcs_bit_present",
                npo_index,
                true,
            )?;
            Self::push_terminal_npo_polynomial_opened_value(
                npo_index, &mut pairs, witness_id, mmcs_value,
            )?;
        } else {
            Self::expect_terminal_npo_polynomial_bool_column(
                columns,
                "mmcs_bit_present",
                npo_index,
                false,
            )?;
            if mmcs_value != F::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: "mmcs_bit".into(),
                        row: npo_index,
                    },
                );
            }
        }

        let expected_witness_ids = Self::npo_callsite_witness_ids(callsite);
        let opened_values = expected_witness_ids
            .iter()
            .map(|expected| {
                pairs
                    .iter()
                    .find(|(witness_id, _)| witness_id == expected)
                    .map(|(_, value)| *value)
                    .ok_or(NativeTerminalVerifyError::MissingWitness {
                        witness_id: expected.0,
                    })
            })
            .collect::<Result<Vec<_>, _>>()?;
        Ok((expected_witness_ids, opened_values))
    }

    fn push_terminal_npo_polynomial_opened_value<F>(
        npo_index: usize,
        pairs: &mut Vec<(WitnessId, F)>,
        witness_id: WitnessId,
        value: F,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: Field,
    {
        if let Some((_, existing)) = pairs.iter().find(|(existing, _)| *existing == witness_id) {
            if *existing != value {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnDuplicateWitnessMismatch {
                        npo_index,
                        witness_id: witness_id.0,
                    },
                );
            }
        } else {
            pairs.push((witness_id, value));
        }
        Ok(())
    }

    fn terminal_npo_polynomial_column_hidden_tip5_inputs<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        npo_index: usize,
        row: usize,
        callsite: &NativeTerminalNpoCallsite,
    ) -> Result<Vec<TerminalTip5HiddenInputValue>, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let mode =
            callsite
                .tip5_mode
                .ok_or(NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                    op_type: Self::tip5_op_type().as_str().into(),
                    row,
                    field: "tip5_mode",
                    limb: 0,
                    expected: Some(1),
                    got: None,
                })?;
        let mmcs_value =
            Self::terminal_npo_polynomial_column_value(columns, "mmcs_bit", npo_index)?;
        let mmcs_bit = mode.merkle_path
            && Self::terminal_npo_table_base_goldilocks(npo_index, "mmcs_bit", &mmcs_value)?
                == Goldilocks::ONE;
        let mut hidden_inputs = Vec::new();
        for trace_limb in 0..columns.layout.hidden_tip5_value_columns {
            let bus_limb =
                Self::terminal_tip5_bus_limb_from_trace_limb(mode, mmcs_bit, trace_limb);
            let expected = callsite
                .inputs
                .get(bus_limb)
                .copied()
                .flatten()
                .is_none();
            let present_label = format!("hidden_tip5_present_{trace_limb}");
            Self::expect_terminal_npo_polynomial_bool_column(
                columns,
                &present_label,
                npo_index,
                expected,
            )?;
            let value_label = format!("hidden_tip5_value_{trace_limb}");
            let value =
                Self::terminal_npo_polynomial_column_value(columns, &value_label, npo_index)?;
            if expected {
                let basis = value.as_basis_coefficients_slice();
                if basis
                    .iter()
                    .copied()
                    .skip(1)
                    .any(|coeff| coeff != Goldilocks::ZERO)
                {
                    return Err(
                        NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                            label: value_label,
                            row: npo_index,
                        },
                    );
                }
                let first = basis.first().copied().unwrap_or(Goldilocks::ZERO);
                hidden_inputs.push(TerminalTip5HiddenInputValue {
                    limb: trace_limb,
                    value_basis: vec![first.as_canonical_u64()],
                });
            } else if value != F::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: value_label,
                        row: npo_index,
                    },
                );
            }
        }
        Ok(hidden_inputs)
    }

    fn expect_terminal_npo_polynomial_no_hidden_tip5_columns<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        npo_index: usize,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: Field,
    {
        for limb in 0..columns.layout.hidden_tip5_value_columns {
            let present_label = format!("hidden_tip5_present_{limb}");
            Self::expect_terminal_npo_polynomial_bool_column(
                columns,
                &present_label,
                npo_index,
                false,
            )?;
            let value_label = format!("hidden_tip5_value_{limb}");
            let value =
                Self::terminal_npo_polynomial_column_value(columns, &value_label, npo_index)?;
            if value != F::ZERO {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: value_label,
                        row: npo_index,
                    },
                );
            }
        }
        Ok(())
    }

    fn terminal_npo_polynomial_column_row_residual_values<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        row: usize,
    ) -> Result<Vec<F>, NativeTerminalVerifyError>
    where
        F: Field,
    {
        let mut values = Vec::new();
        for slot in 0..columns.layout.residual_value_columns {
            let present_label = format!("residual_present_{slot}");
            let present = Self::terminal_npo_polynomial_column_value(columns, &present_label, row)?;
            let value_label = format!("residual_value_{slot}");
            let value = Self::terminal_npo_polynomial_column_value(columns, &value_label, row)?;
            if present == F::ONE {
                values.push(value);
            } else if present == F::ZERO {
                if value != F::ZERO {
                    return Err(
                        NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                            label: value_label,
                            row,
                        },
                    );
                }
            } else {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: present_label,
                        row,
                    },
                );
            }
        }
        Ok(values)
    }

    fn validate_terminal_npo_polynomial_columns<F>(
        layout: &TerminalNpoPolynomialColumnLayout,
        columns: &TerminalNpoPolynomialColumns<F>,
    ) -> Result<(), NativeTerminalVerifyError> {
        if columns.labels.len() != layout.column_count
            || columns.columns.len() != layout.column_count
        {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: "columns".into(),
                    expected: layout.column_count,
                    got: columns.columns.len(),
                },
            );
        }
        let expected_labels = Self::terminal_npo_polynomial_column_labels(layout);
        for (index, expected) in expected_labels.iter().enumerate() {
            if columns.labels.get(index) != Some(expected) {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: expected.clone(),
                        row: 0,
                    },
                );
            }
        }
        for (label, column) in columns.labels.iter().zip(&columns.columns) {
            if columns
                .labels
                .iter()
                .filter(|candidate| *candidate == label)
                .count()
                != 1
            {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                        label: label.clone(),
                        row: 0,
                    },
                );
            }
            if column.len() != layout.rows {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                        label: label.clone(),
                        expected: layout.rows,
                        got: column.len(),
                    },
                );
            }
        }
        Ok(())
    }

    fn expect_terminal_npo_polynomial_bool_column<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        label: &str,
        row: usize,
        expected: bool,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: Field,
    {
        let expected = if expected { F::ONE } else { F::ZERO };
        let got = Self::terminal_npo_polynomial_column_value(columns, label, row)?;
        if got != expected {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialColumnValueMismatch {
                    label: label.into(),
                    row,
                },
            );
        }
        Ok(())
    }

    fn terminal_npo_polynomial_column_value<F>(
        columns: &TerminalNpoPolynomialColumns<F>,
        label: &str,
        row: usize,
    ) -> Result<F, NativeTerminalVerifyError>
    where
        F: Copy,
    {
        let column_index = columns
            .labels
            .iter()
            .position(|candidate| candidate == label)
            .ok_or_else(
                || NativeTerminalVerifyError::TerminalNpoPolynomialColumnMissing {
                    label: label.into(),
                },
            )?;
        columns.columns[column_index]
            .get(row)
            .copied()
            .ok_or_else(
                || NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch {
                    label: label.into(),
                    expected: row + 1,
                    got: columns.columns[column_index].len(),
                },
            )
    }

    fn max_serialized_tip5_hidden_input_slots(
        callsite: &NativeTerminalNpoCallsite,
        mode: Tip5TerminalMode,
    ) -> usize {
        if !mode.merkle_path {
            return 0;
        }
        let mut count_without_swap = 0usize;
        let mut count_with_swap = 0usize;
        for trace_limb in 0..16 {
            if Self::should_serialize_tip5_hidden_limb(callsite, mode, false, trace_limb) {
                count_without_swap += 1;
            }
            if Self::should_serialize_tip5_hidden_limb(callsite, mode, true, trace_limb) {
                count_with_swap += 1;
            }
        }
        count_without_swap.max(count_with_swap)
    }

    fn terminal_npo_exhaustive_residual_domain_len_for_basis_dimension<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        basis_dimension: usize,
    ) -> usize {
        (0..Self::terminal_npo_domain_len(verifying_key))
            .map(|npo_index| {
                Self::terminal_npo_row(verifying_key, npo_index)
                    .map(|row| {
                        Self::terminal_npo_exhaustive_residual_component_count_for_basis_dimension(
                            &row,
                            basis_dimension,
                        )
                    })
                    .unwrap_or(0)
            })
            .sum()
    }

    fn terminal_npo_exhaustive_residual_component_row<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        residual_index: usize,
    ) -> Option<TerminalNpoResidualComponentRef>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::terminal_npo_exhaustive_residual_component_row_for_basis_dimension(
            verifying_key,
            residual_index,
            <F as BasedVectorSpace<Goldilocks>>::DIMENSION,
        )
    }

    fn terminal_npo_exhaustive_residual_segment_indices<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        npo_index: usize,
    ) -> Result<Vec<usize>, NativeTerminalVerifyError> {
        let target_row = Self::terminal_npo_row(verifying_key, npo_index).ok_or(
            NativeTerminalVerifyError::TerminalNpoQueryIndexMismatch {
                query: 0,
                expected: npo_index,
                got: npo_index,
            },
        )?;
        let target_mode = match target_row {
            NativeTerminalNpoRowRef::Recompose { .. } => return Ok(vec![npo_index]),
            NativeTerminalNpoRowRef::Tip5 { row, callsite, .. } => callsite.tip5_mode.ok_or(
                NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                    op_type: Self::tip5_op_type().as_str().into(),
                    row,
                    field: "tip5_mode",
                    limb: 0,
                    expected: Some(1),
                    got: None,
                },
            )?,
        };

        let mut segment = Vec::new();
        for candidate in 0..=npo_index {
            let Some(NativeTerminalNpoRowRef::Tip5 { row, callsite, .. }) =
                Self::terminal_npo_row(verifying_key, candidate)
            else {
                continue;
            };
            let mode = callsite.tip5_mode.ok_or(
                NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                    op_type: Self::tip5_op_type().as_str().into(),
                    row,
                    field: "tip5_mode",
                    limb: 0,
                    expected: Some(1),
                    got: None,
                },
            )?;
            if mode.merkle_path != target_mode.merkle_path {
                continue;
            }
            if mode.new_start {
                segment.clear();
            }
            segment.push(candidate);
        }
        if segment.last().copied() != Some(npo_index) {
            return Err(NativeTerminalVerifyError::TerminalNpoQueryIndexMismatch {
                query: 0,
                expected: npo_index,
                got: segment.last().copied().unwrap_or(npo_index),
            });
        }
        Ok(segment)
    }

    fn terminal_npo_exhaustive_residual_component_row_for_basis_dimension<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        residual_index: usize,
        basis_dimension: usize,
    ) -> Option<TerminalNpoResidualComponentRef> {
        let mut base = 0usize;
        for npo_index in 0..Self::terminal_npo_domain_len(verifying_key) {
            let row = Self::terminal_npo_row(verifying_key, npo_index)?;
            let count = Self::terminal_npo_exhaustive_residual_component_count_for_basis_dimension(
                &row,
                basis_dimension,
            );
            if residual_index < base + count {
                let mut component =
                    Self::terminal_npo_exhaustive_row_component_for_basis_dimension(
                        &row,
                        residual_index - base,
                        basis_dimension,
                    )?;
                component.npo_index = npo_index;
                return Some(component);
            }
            base += count;
        }
        None
    }

    fn terminal_npo_exhaustive_row_component_for_basis_dimension(
        row: &NativeTerminalNpoRowRef<'_>,
        component_offset: usize,
        basis_dimension: usize,
    ) -> Option<TerminalNpoResidualComponentRef> {
        let mut base = 0usize;
        let mut component = |kind: TerminalNpoResidualKind,
                             limb: usize,
                             width: usize|
         -> Option<TerminalNpoResidualComponentRef> {
            if component_offset < base + width {
                Some(TerminalNpoResidualComponentRef {
                    npo_index: 0,
                    component_offset,
                    kind,
                    limb,
                    basis_component: component_offset - base,
                })
            } else {
                base += width;
                None
            }
        };

        match row {
            NativeTerminalNpoRowRef::Tip5 { callsite, .. } => {
                for (limb, witness_id) in callsite.inputs.iter().enumerate() {
                    if witness_id.is_some() {
                        if let Some(component) =
                            component(TerminalNpoResidualKind::Tip5Input, limb, basis_dimension)
                        {
                            return Some(component);
                        }
                    }
                }
                for (limb, witness_id) in callsite.outputs.iter().enumerate() {
                    if witness_id.is_some() {
                        if let Some(component) =
                            component(TerminalNpoResidualKind::Tip5Output, limb, basis_dimension)
                        {
                            return Some(component);
                        }
                    }
                }
                let Some(mode) = callsite.tip5_mode else {
                    return None;
                };
                if mode.merkle_path
                    && callsite.tip5_mmcs_bit.is_some()
                    && let Some(component) = component(TerminalNpoResidualKind::Tip5MmcsBit, 16, 1)
                {
                    return Some(component);
                }
                if mode.merkle_path {
                    for limb in 0..5 {
                        if callsite.inputs[limb].is_none()
                            && let Some(component) =
                                component(TerminalNpoResidualKind::Tip5ChainInput, limb, 1)
                        {
                            return Some(component);
                        }
                    }
                    for limb in 10..16 {
                        if callsite.inputs[limb].is_none()
                            && let Some(component) =
                                component(TerminalNpoResidualKind::Tip5ChainInput, limb, 1)
                        {
                            return Some(component);
                        }
                    }
                } else {
                    for limb in 0..16 {
                        if callsite.inputs[limb].is_none()
                            && let Some(component) =
                                component(TerminalNpoResidualKind::Tip5ChainInput, limb, 1)
                        {
                            return Some(component);
                        }
                    }
                }
                None
            }
            NativeTerminalNpoRowRef::Recompose { callsite, .. } => {
                for limb in 0..callsite.inputs.len() {
                    if let Some(component) = component(
                        TerminalNpoResidualKind::RecomposeInput,
                        limb,
                        basis_dimension,
                    ) {
                        return Some(component);
                    }
                }
                if callsite.outputs.first().copied().flatten().is_some() {
                    if let Some(component) =
                        component(TerminalNpoResidualKind::RecomposeOutput, 0, basis_dimension)
                    {
                        return Some(component);
                    }
                }
                None
            }
        }
    }

    fn terminal_npo_exhaustive_residual_component_count_for_basis_dimension(
        row: &NativeTerminalNpoRowRef<'_>,
        basis_dimension: usize,
    ) -> usize {
        let sampled_components =
            Self::terminal_npo_validity_component_count_for_basis_dimension(row, basis_dimension);
        match row {
            NativeTerminalNpoRowRef::Tip5 { callsite, .. } => {
                let Some(mode) = callsite.tip5_mode else {
                    return sampled_components;
                };
                let mut exhaustive_components = sampled_components;
                if mode.merkle_path && callsite.tip5_mmcs_bit.is_some() {
                    exhaustive_components += 1;
                }
                exhaustive_components
                    + Self::terminal_tip5_chain_residual_component_count(callsite, mode)
            }
            NativeTerminalNpoRowRef::Recompose { .. } => sampled_components,
        }
    }

    fn terminal_tip5_chain_residual_component_count(
        callsite: &NativeTerminalNpoCallsite,
        mode: Tip5TerminalMode,
    ) -> usize {
        if mode.merkle_path {
            let chained_rate_lanes = (0..5)
                .filter(|limb| callsite.inputs[*limb].is_none())
                .count();
            let zero_capacity_lanes = (10..16)
                .filter(|limb| callsite.inputs[*limb].is_none())
                .count();
            chained_rate_lanes + zero_capacity_lanes
        } else {
            callsite
                .inputs
                .iter()
                .filter(|input| input.is_none())
                .count()
        }
    }

    fn terminal_npo_validity_domain_len<F>(verifying_key: &NativeTerminalVerifyingKey<F>) -> usize
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::terminal_npo_validity_domain_len_for_basis_dimension(
            verifying_key,
            <F as BasedVectorSpace<Goldilocks>>::DIMENSION,
        )
    }

    fn terminal_npo_validity_domain_len_for_basis_dimension<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        basis_dimension: usize,
    ) -> usize {
        (0..Self::terminal_npo_domain_len(verifying_key))
            .map(|npo_index| {
                Self::terminal_npo_row(verifying_key, npo_index)
                    .map(|row| {
                        Self::terminal_npo_validity_component_count_for_basis_dimension(
                            &row,
                            basis_dimension,
                        )
                    })
                    .unwrap_or(0)
            })
            .sum()
    }

    fn terminal_npo_validity_component_count<F>(row: &NativeTerminalNpoRowRef<'_>) -> usize
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        Self::terminal_npo_validity_component_count_for_basis_dimension(
            row,
            <F as BasedVectorSpace<Goldilocks>>::DIMENSION,
        )
    }

    fn terminal_npo_validity_component_count_for_basis_dimension(
        row: &NativeTerminalNpoRowRef<'_>,
        basis_dimension: usize,
    ) -> usize {
        match row {
            NativeTerminalNpoRowRef::Tip5 { callsite, .. } => {
                let input_components = callsite
                    .inputs
                    .iter()
                    .filter(|input| input.is_some())
                    .count();
                let output_components = callsite
                    .outputs
                    .iter()
                    .filter(|output| output.is_some())
                    .count();
                (input_components + output_components) * basis_dimension
            }
            NativeTerminalNpoRowRef::Recompose { callsite, .. } => {
                let input_components = callsite.inputs.len() * basis_dimension;
                let output_components = if callsite.outputs.first().copied().flatten().is_some() {
                    basis_dimension
                } else {
                    0
                };
                input_components + output_components
            }
        }
    }

    fn terminal_npo_validity_component_row<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        validity_index: usize,
    ) -> Option<(usize, usize)>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        let mut base = 0usize;
        for npo_index in 0..Self::terminal_npo_domain_len(verifying_key) {
            let row = Self::terminal_npo_row(verifying_key, npo_index)?;
            let count = Self::terminal_npo_validity_component_count::<F>(&row);
            if validity_index < base + count {
                return Some((npo_index, validity_index - base));
            }
            base += count;
        }
        None
    }

    fn terminal_npo_row<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        npo_index: usize,
    ) -> Option<NativeTerminalNpoRowRef<'_>> {
        let mut base = 0usize;
        for constraint in &verifying_key.constraints {
            match constraint {
                NativeTerminalConstraint::Tip5Goldilocks {
                    op_type,
                    expected_rows,
                    callsites,
                } => {
                    let end = base + *expected_rows;
                    if npo_index < end {
                        let row = npo_index - base;
                        return Some(NativeTerminalNpoRowRef::Tip5 {
                            op_type,
                            row,
                            callsite: &callsites[row],
                        });
                    }
                    base = end;
                }
                NativeTerminalConstraint::RecomposeGoldilocks {
                    op_type,
                    expected_rows,
                    callsites,
                } => {
                    let end = base + *expected_rows;
                    if npo_index < end {
                        let row = npo_index - base;
                        return Some(NativeTerminalNpoRowRef::Recompose {
                            op_type,
                            row,
                            callsite: &callsites[row],
                        });
                    }
                    base = end;
                }
                _ => {}
            }
        }
        None
    }

    fn npo_callsite_witness_ids(callsite: &NativeTerminalNpoCallsite) -> Vec<WitnessId> {
        let mut out = Vec::new();
        for witness_id in callsite.inputs.iter().chain(&callsite.outputs).flatten() {
            Self::push_unique_witness(&mut out, *witness_id);
        }
        if let Some(witness_id) = callsite.tip5_mmcs_bit {
            Self::push_unique_witness(&mut out, witness_id);
        }
        out
    }

    fn push_unique_witness(out: &mut Vec<WitnessId>, witness_id: WitnessId) {
        if !out.iter().any(|existing| *existing == witness_id) {
            out.push(witness_id);
        }
    }

    fn push_unique_usize(out: &mut Vec<usize>, value: usize) {
        if !out.iter().any(|existing| *existing == value) {
            out.push(value);
        }
    }

    fn verify_sampled_primitive_constraint<F: Field>(
        constraint_index: usize,
        constraint: &NativeTerminalConstraint<F>,
        public_inputs: &[F],
        witness_ids: &[WitnessId],
        values: &[F],
    ) -> Result<(), NativeTerminalVerifyError> {
        let value = |wanted: WitnessId| {
            witness_ids
                .iter()
                .position(|id| *id == wanted)
                .map(|idx| values[idx])
                .ok_or(NativeTerminalVerifyError::MissingWitness {
                    witness_id: wanted.0,
                })
        };

        match constraint {
            NativeTerminalConstraint::Const { out, val } => {
                if value(*out)? != *val {
                    return Err(NativeTerminalVerifyError::ConstraintViolation {
                        constraint_index,
                        kind: "sampled_const",
                    });
                }
            }
            NativeTerminalConstraint::Public { out, public_pos } => {
                let Some(public_value) = public_inputs.get(*public_pos).copied() else {
                    return Err(NativeTerminalVerifyError::PublicInputLengthMismatch {
                        expected: *public_pos + 1,
                        got: public_inputs.len(),
                    });
                };
                if value(*out)? != public_value {
                    return Err(NativeTerminalVerifyError::PublicInputMismatch {
                        public_pos: *public_pos,
                    });
                }
            }
            NativeTerminalConstraint::Alu {
                kind,
                a,
                b,
                c,
                out,
                intermediate_out,
            } => {
                let a_val = value(*a)?;
                let b_val = value(*b)?;
                let c_val = if let Some(c) = c { value(*c)? } else { F::ZERO };
                let out_val = value(*out)?;
                let ok = match kind {
                    AluOpKind::Add => a_val + b_val == out_val,
                    AluOpKind::Mul => a_val * b_val == out_val,
                    AluOpKind::BoolCheck => a_val * (a_val - F::ONE) == F::ZERO && out_val == a_val,
                    AluOpKind::MulAdd => a_val * b_val + c_val == out_val,
                    AluOpKind::HornerAcc => {
                        let Some(acc) = intermediate_out else {
                            return Err(NativeTerminalVerifyError::ConstraintViolation {
                                constraint_index,
                                kind: "sampled_horner_acc_missing_acc",
                            });
                        };
                        value(*acc)? * b_val + c_val - a_val == out_val
                    }
                };
                if !ok {
                    return Err(NativeTerminalVerifyError::ConstraintViolation {
                        constraint_index,
                        kind: "sampled_alu",
                    });
                }
            }
            NativeTerminalConstraint::Tip5Goldilocks { .. }
            | NativeTerminalConstraint::RecomposeGoldilocks { .. } => {
                return Err(NativeTerminalVerifyError::ConstraintViolation {
                    constraint_index,
                    kind: "sampled_nonprimitive_not_in_primitive_domain",
                });
            }
        }
        Ok(())
    }

    fn prove_terminal_npo_opening_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        witness_oracle: &TerminalOracleMerkleTree,
        witness: &TerminalWitness<F>,
        npo_index: usize,
    ) -> Result<TerminalNpoOpening, NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let (local_opening, expected_witness_ids) =
            self.terminal_npo_local_opening_goldilocks(verifying_key, witness, npo_index)?;
        let mut witness_openings = Vec::new();
        let mut opened_values = Vec::with_capacity(expected_witness_ids.len());
        for witness_id in &expected_witness_ids {
            let value = witness.traces.witness_trace.get_value(*witness_id).ok_or(
                NativeTerminalVerifyError::MissingWitness {
                    witness_id: witness_id.0,
                },
            )?;
            opened_values.push(*value);
            witness_openings
                .push(witness_oracle.open_goldilocks_value(witness_id.0 as usize, value)?);
        }
        let (row, callsite) = match Self::terminal_npo_row(verifying_key, npo_index).ok_or(
            NativeTerminalVerifyError::TerminalNpoQueryIndexMismatch {
                query: npo_index,
                expected: npo_index,
                got: npo_index,
            },
        )? {
            NativeTerminalNpoRowRef::Tip5 { row, callsite, .. } => (row, callsite),
            NativeTerminalNpoRowRef::Recompose { .. } => {
                return Ok(TerminalNpoOpening {
                    npo_index,
                    tip5_hidden_input_values: Vec::new(),
                    witness_openings,
                });
            }
        };

        Ok(TerminalNpoOpening {
            npo_index,
            tip5_hidden_input_values:
                Self::terminal_tip5_hidden_inputs_from_compact_for_opened_values(
                local_opening.npo_index,
                row,
                callsite,
                local_opening.tip5_hidden_input_nonzero_mask,
                &local_opening.tip5_hidden_input_values_le,
                &expected_witness_ids,
                &opened_values,
            )?,
            witness_openings,
        })
    }

    fn terminal_npo_local_opening_goldilocks<F>(
        &self,
        verifying_key: &NativeTerminalVerifyingKey<F>,
        witness: &TerminalWitness<F>,
        npo_index: usize,
    ) -> Result<(TerminalNpoLocalOpening, Vec<WitnessId>), NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let row_ref = Self::terminal_npo_row(verifying_key, npo_index).ok_or(
            NativeTerminalVerifyError::TerminalNpoQueryIndexMismatch {
                query: 0,
                expected: npo_index,
                got: npo_index,
            },
        )?;
        let mut tip5_hidden_input_nonzero_mask = 0u16;
        let mut tip5_hidden_input_values_le = Vec::new();
        let expected_witness_ids = match row_ref {
            NativeTerminalNpoRowRef::Tip5 {
                op_type,
                row,
                callsite,
            } => {
                let trace = witness
                    .traces
                    .non_primitive_traces
                    .get(&NpoTypeId::new(op_type))
                    .and_then(|trace| trace.as_any().downcast_ref::<Tip5Trace<Goldilocks>>())
                    .ok_or_else(|| NativeTerminalVerifyError::MissingNonPrimitiveTrace {
                        op_type: op_type.into(),
                    })?;
                let operation = trace.operations.get(row).ok_or_else(|| {
                    NativeTerminalVerifyError::NonPrimitiveTraceRowCount {
                        op_type: op_type.into(),
                        expected: row + 1,
                        got: trace.operations.len(),
                    }
                })?;
                Self::verify_tip5_callsite(op_type, row, callsite, operation)?;
                if operation.input_values.len() != 16 {
                    return Err(NativeTerminalVerifyError::Tip5TraceInputLength {
                        row,
                        got: operation.input_values.len(),
                    });
                }
                let mode = callsite.tip5_mode.ok_or(
                    NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                        op_type: op_type.into(),
                        row,
                        field: "tip5_mode",
                        limb: 0,
                        expected: Some(1),
                        got: None,
                    },
                )?;
                let mmcs_bit = mode.merkle_path && operation.mmcs_bit;
                for (trace_limb, input_value) in operation.input_values.iter().enumerate() {
                    let bus_limb =
                        Self::terminal_tip5_bus_limb_from_trace_limb(mode, mmcs_bit, trace_limb);
                    if callsite
                        .inputs
                        .get(bus_limb)
                        .copied()
                        .flatten()
                        .is_none()
                    {
                        let basis = Self::goldilocks_basis_u64(input_value);
                        if basis.len() != 1 {
                            return Err(
                                NativeTerminalVerifyError::TerminalNpoTip5InputValueDimensionMismatch {
                                    npo_index,
                                    limb: trace_limb,
                                    expected: 1,
                                    got: basis.len(),
                                },
                            );
                        }
                        if basis[0] != 0 {
                            tip5_hidden_input_nonzero_mask |= 1u16 << trace_limb;
                            tip5_hidden_input_values_le.push(basis[0].to_le_bytes());
                        }
                    }
                }
                Self::npo_callsite_witness_ids(callsite)
            }
            NativeTerminalNpoRowRef::Recompose { callsite, .. } => {
                Self::npo_callsite_witness_ids(callsite)
            }
        };

        Ok((
            TerminalNpoLocalOpening {
                npo_index,
                tip5_hidden_input_nonzero_mask,
                tip5_hidden_input_values_le,
            },
            expected_witness_ids,
        ))
    }

    fn terminal_tip5_hidden_inputs_from_compact_for_opened_values<F>(
        npo_index: usize,
        row: usize,
        callsite: &NativeTerminalNpoCallsite,
        nonzero_mask: u16,
        values_le: &[[u8; 8]],
        expected_witness_ids: &[WitnessId],
        opened_values: &[F],
    ) -> Result<Vec<TerminalTip5HiddenInputValue>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks> + Copy,
    {
        let mode =
            callsite
                .tip5_mode
                .ok_or(NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                    op_type: Self::tip5_op_type().as_str().into(),
                    row,
                    field: "tip5_mode",
                    limb: 0,
                    expected: Some(1),
                    got: None,
                })?;
        let mmcs_bit = if mode.merkle_path {
            let witness_id = callsite.tip5_mmcs_bit.ok_or(
                NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                    op_type: Self::tip5_op_type().as_str().into(),
                    row,
                    field: "mmcs_bit",
                    limb: 16,
                    expected: Some(1),
                    got: None,
                },
            )?;
            Self::tip5_opened_goldilocks_value(
                row,
                16,
                expected_witness_ids,
                opened_values,
                witness_id,
            )? == Goldilocks::ONE
        } else {
            false
        };

        if values_le.len() != nonzero_mask.count_ones() as usize {
            return Err(NativeTerminalVerifyError::TerminalNpoTip5InputValueLength {
                npo_index,
                expected: nonzero_mask.count_ones() as usize,
                got: values_le.len(),
            });
        }
        let mut hidden_mask = 0u16;
        let mut hidden_input_count = 0usize;
        for trace_limb in 0..16 {
            let bus_limb = Self::terminal_tip5_bus_limb_from_trace_limb(
                mode, mmcs_bit, trace_limb,
            );
            if callsite.inputs.get(bus_limb).copied().flatten().is_none() {
                hidden_mask |= 1u16 << trace_limb;
                hidden_input_count += 1;
            }
        }
        if (nonzero_mask & !hidden_mask) != 0 {
            return Err(NativeTerminalVerifyError::TerminalNpoTip5InputValueLength {
                npo_index,
                expected: hidden_input_count,
                got: nonzero_mask.count_ones() as usize,
            });
        }
        let mut values = Vec::with_capacity(hidden_input_count);
        let mut value_index = 0usize;
        for limb in 0..16 {
            if (hidden_mask & (1u16 << limb)) != 0 {
                let value = if (nonzero_mask & (1u16 << limb)) != 0 {
                    let value = u64::from_le_bytes(values_le[value_index]);
                    value_index += 1;
                    value
                } else {
                    0
                };
                values.push(TerminalTip5HiddenInputValue {
                    limb,
                    value_basis: vec![value],
                });
            }
        }
        Ok(values)
    }

    fn terminal_tip5_hidden_inputs_from_exhaustive_compact<F>(
        npo_index: usize,
        row: usize,
        callsite: &NativeTerminalNpoCallsite,
        values_le: &[[u8; 8]],
        value_offset: &mut usize,
        expected_witness_ids: &[WitnessId],
        opened_values: &[F],
        previous_normal_output: &Option<[Goldilocks; 16]>,
        previous_merkle_output: &Option<[Goldilocks; 16]>,
    ) -> Result<Vec<TerminalTip5HiddenInputValue>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks> + Copy,
    {
        let mode =
            callsite
                .tip5_mode
                .ok_or(NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                    op_type: Self::tip5_op_type().as_str().into(),
                    row,
                    field: "tip5_mode",
                    limb: 0,
                    expected: Some(1),
                    got: None,
                })?;
        let mmcs_bit = if mode.merkle_path {
            let witness_id = callsite.tip5_mmcs_bit.ok_or(
                NativeTerminalVerifyError::NonPrimitiveCallsiteMismatch {
                    op_type: Self::tip5_op_type().as_str().into(),
                    row,
                    field: "mmcs_bit",
                    limb: 16,
                    expected: Some(1),
                    got: None,
                },
            )?;
            let value = Self::tip5_opened_goldilocks_value(
                row,
                16,
                expected_witness_ids,
                opened_values,
                witness_id,
            )?;
            if value == Goldilocks::ZERO {
                false
            } else if value == Goldilocks::ONE {
                true
            } else {
                return Err(NativeTerminalVerifyError::Tip5InputMismatch { row, limb: 16 });
            }
        } else {
            false
        };
        let mut values = Vec::new();
        for trace_limb in 0..16 {
            let bus_limb =
                Self::terminal_tip5_bus_limb_from_trace_limb(mode, mmcs_bit, trace_limb);
            if callsite
                .inputs
                .get(bus_limb)
                .copied()
                .flatten()
                .is_some()
            {
                continue;
            }
            let serialized = Self::should_serialize_tip5_hidden_limb(
                callsite,
                mode,
                mmcs_bit,
                trace_limb,
            );
            let value = if serialized {
                let Some(value_le) = values_le.get(*value_offset) else {
                    return Err(NativeTerminalVerifyError::TerminalNpoTip5InputValueLength {
                        npo_index,
                        expected: *value_offset + 1,
                        got: values_le.len(),
                    });
                };
                *value_offset += 1;
                u64::from_le_bytes(*value_le)
            } else if mode.merkle_path {
                if bus_limb < 5 {
                    if mode.new_start {
                        0
                    } else {
                        previous_merkle_output.ok_or(
                            NativeTerminalVerifyError::Tip5InputMismatch {
                                row,
                                limb: trace_limb,
                            },
                        )?[bus_limb]
                            .as_canonical_u64()
                    }
                } else if bus_limb >= 10 {
                    0
                } else {
                    0
                }
            } else if mode.new_start {
                0
            } else {
                previous_normal_output.ok_or(NativeTerminalVerifyError::Tip5InputMismatch {
                    row,
                    limb: trace_limb,
                })?[trace_limb]
                    .as_canonical_u64()
            };
            values.push(TerminalTip5HiddenInputValue {
                limb: trace_limb,
                value_basis: vec![value],
            });
        }
        Ok(values)
    }

    fn verify_npo_witness_openings<F>(
        &self,
        npo_index: usize,
        expected_witness_ids: &[WitnessId],
        witness_commitment: &TerminalOracleCommitment,
        openings: &[TerminalOracleOpening],
    ) -> Result<Vec<F>, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks>,
    {
        if openings.len() != expected_witness_ids.len() {
            return Err(NativeTerminalVerifyError::TerminalNpoOpeningCountMismatch {
                npo_index,
                expected: expected_witness_ids.len(),
                got: openings.len(),
            });
        }

        let mut values = Vec::with_capacity(openings.len());
        for (opening_idx, (expected_witness, opening)) in expected_witness_ids
            .iter()
            .copied()
            .zip(openings)
            .enumerate()
        {
            if opening.index != expected_witness.0 as usize {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoOpeningWitnessMismatch {
                        npo_index,
                        opening: opening_idx,
                        expected: expected_witness.0,
                        got: opening.index,
                    },
                );
            }
            self.verify_terminal_oracle_opening(witness_commitment, opening)?;
            values.push(Self::field_from_goldilocks_basis_u64::<F>(
                &opening.value_basis,
            )?);
        }
        Ok(values)
    }

    fn verify_npo_witness_values<F>(
        npo_index: usize,
        expected_witness_ids: &[WitnessId],
        opened_witness_values: &[(usize, F)],
    ) -> Result<Vec<F>, NativeTerminalVerifyError>
    where
        F: Copy,
    {
        let mut values = Vec::with_capacity(expected_witness_ids.len());
        for (opening_idx, expected_witness) in expected_witness_ids.iter().copied().enumerate() {
            let index = expected_witness.0 as usize;
            let Ok(position) =
                opened_witness_values.binary_search_by_key(&index, |(index, _)| *index)
            else {
                return Err(
                    NativeTerminalVerifyError::TerminalNpoOpeningWitnessMismatch {
                        npo_index,
                        opening: opening_idx,
                        expected: expected_witness.0,
                        got: index,
                    },
                );
            };
            values.push(opened_witness_values[position].1);
        }
        Ok(values)
    }

    fn tip5_opened_goldilocks_value<F>(
        row: usize,
        limb: usize,
        expected_witness_ids: &[WitnessId],
        opened_values: &[F],
        wanted: WitnessId,
    ) -> Result<Goldilocks, NativeTerminalVerifyError>
    where
        F: BasedVectorSpace<Goldilocks> + Copy,
    {
        let value = expected_witness_ids
            .iter()
            .position(|id| *id == wanted)
            .map(|idx| opened_values[idx])
            .ok_or(NativeTerminalVerifyError::MissingWitness {
                witness_id: wanted.0,
            })?;
        let basis = value.as_basis_coefficients_slice();
        if basis
            .iter()
            .copied()
            .skip(1)
            .any(|coeff| coeff != Goldilocks::ZERO)
        {
            return Err(NativeTerminalVerifyError::Tip5InputMismatch { row, limb });
        }
        Ok(basis[0])
    }

    fn apply_terminal_tip5_merkle_swap(state: &mut [Goldilocks; 16]) {
        for limb in 0..5 {
            state.swap(limb, 5 + limb);
        }
    }

    fn terminal_tip5_bus_limb_from_trace_limb(
        mode: Tip5TerminalMode,
        mmcs_bit: bool,
        trace_limb: usize,
    ) -> usize {
        if mode.merkle_path && mmcs_bit {
            Self::terminal_tip5_merkle_swapped_limb(trace_limb)
        } else {
            trace_limb
        }
    }

    fn terminal_tip5_merkle_swapped_limb(limb: usize) -> usize {
        if limb < 5 {
            limb + 5
        } else if limb < 10 {
            limb - 5
        } else {
            limb
        }
    }

    fn should_serialize_tip5_hidden_limb(
        callsite: &NativeTerminalNpoCallsite,
        mode: Tip5TerminalMode,
        mmcs_bit: bool,
        trace_limb: usize,
    ) -> bool {
        if !mode.merkle_path {
            return false;
        }
        let bus_limb = Self::terminal_tip5_bus_limb_from_trace_limb(mode, mmcs_bit, trace_limb);
        if callsite
            .inputs
            .get(bus_limb)
            .copied()
            .flatten()
            .is_some()
        {
            return false;
        }
        (5..10).contains(&bus_limb)
    }

    fn terminal_fold_round_indices(
        initial_indices: &[usize],
        base_len: usize,
        rounds: usize,
    ) -> Vec<Vec<usize>> {
        let mut expected_round_indices = vec![Vec::new(); rounds];
        for initial_index in initial_indices {
            let mut index = *initial_index;
            let mut current_len = base_len;
            for round_indices in &mut expected_round_indices {
                let pair_index = (index / 2) * 2;
                Self::push_unique_usize(round_indices, pair_index);
                if pair_index + 1 < current_len {
                    Self::push_unique_usize(round_indices, pair_index + 1);
                }
                index /= 2;
                current_len = current_len.div_ceil(2);
            }
        }
        for round_indices in &mut expected_round_indices {
            round_indices.sort_unstable();
        }
        expected_round_indices
    }

    fn verify_terminal_oracle_value_indices<F>(
        expected_indices: &[usize],
        opened_values: &[(usize, F)],
    ) -> Result<(), NativeTerminalVerifyError> {
        if opened_values.len() != expected_indices.len() {
            return Err(
                NativeTerminalVerifyError::TerminalOracleQueryLengthMismatch {
                    expected: expected_indices.len(),
                    got: opened_values.len(),
                },
            );
        }
        for (query, (expected, (got, _))) in expected_indices.iter().zip(opened_values).enumerate()
        {
            if got != expected {
                return Err(
                    NativeTerminalVerifyError::TerminalOracleQueryIndexMismatch {
                        query,
                        expected: *expected,
                        got: *got,
                    },
                );
            }
        }
        Ok(())
    }

    fn terminal_opened_value<F>(
        opened_values: &[(usize, F)],
        index: usize,
    ) -> Result<F, NativeTerminalVerifyError>
    where
        F: Copy,
    {
        let position = opened_values
            .binary_search_by_key(&index, |(opened_index, _)| *opened_index)
            .map_err(
                |_| NativeTerminalVerifyError::TerminalOracleQueryIndexMismatch {
                    query: 0,
                    expected: index,
                    got: index,
                },
            )?;
        Ok(opened_values[position].1)
    }

    fn verify_prelude_binds_commitment(
        prelude: &TerminalProofPrelude,
        commitment: &TerminalOracleCommitment,
    ) -> Result<(), NativeTerminalVerifyError> {
        if !prelude
            .commitments
            .iter()
            .any(|bound_root| *bound_root == commitment.root)
        {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentNotBound {
                    root: commitment.root,
                },
            );
        }
        Ok(())
    }

    fn verify_standalone_oracle_prelude_commitment(
        prelude: &TerminalProofPrelude,
        commitment: &TerminalOracleCommitment,
    ) -> Result<(), NativeTerminalVerifyError> {
        let expected = [commitment.root];
        if prelude.commitments.len() != expected.len() {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentCountMismatch {
                    expected: expected.len(),
                    got: prelude.commitments.len(),
                },
            );
        }
        if prelude.commitments[0] != expected[0] {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentMismatch {
                    index: 0,
                    expected: expected[0],
                    got: prelude.commitments[0],
                },
            );
        }
        Ok(())
    }

    pub fn terminal_fri_commitment_digest(
        commitment: &TerminalFriCommitment,
    ) -> Result<TerminalCommitmentDigest, NativeTerminalVerifyError> {
        if commitment.num_roots() != 1 {
            return Err(
                NativeTerminalVerifyError::TerminalNpoPolynomialFriVerification {
                    reason: format!(
                        "terminal FRI commitment cap must have one root, got {}",
                        commitment.num_roots()
                    ),
                },
            );
        }
        let root = commitment.roots()[0];
        Ok(TerminalCommitmentDigest(
            root.map(|limb| limb.as_canonical_u64()),
        ))
    }

    fn verify_terminal_fri_prelude_commitments(
        prelude: &TerminalProofPrelude,
        expected: &[TerminalCommitmentDigest],
    ) -> Result<(), NativeTerminalVerifyError> {
        if expected.is_empty() {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentCountMismatch {
                    expected: 1,
                    got: expected.len(),
                },
            );
        }
        if prelude.commitments.len() < expected.len() {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentCountMismatch {
                    expected: expected.len(),
                    got: prelude.commitments.len(),
                },
            );
        }

        if prelude
            .commitments
            .windows(expected.len())
            .any(|candidate| candidate == expected)
        {
            return Ok(());
        }

        for (index, expected_root) in expected.iter().enumerate() {
            if let Some(got) = prelude.commitments.get(index) {
                if got != expected_root {
                    return Err(
                        NativeTerminalVerifyError::TerminalPreludeCommitmentMismatch {
                            index,
                            expected: *expected_root,
                            got: *got,
                        },
                    );
                }
            }
        }
        Err(
            NativeTerminalVerifyError::TerminalPreludeCommitmentMismatch {
                index: 0,
                expected: expected[0],
                got: prelude.commitments[0],
            },
        )
    }

    fn verify_production_prelude_commitments(
        prelude: &TerminalProofPrelude,
        assignment_commitment: &TerminalOracleCommitment,
        expected_len: usize,
    ) -> Result<(), NativeTerminalVerifyError> {
        if prelude.commitments.len() != expected_len {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentCountMismatch {
                    expected: expected_len,
                    got: prelude.commitments.len(),
                },
            );
        }
        if prelude.commitments[0] != assignment_commitment.root {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentMismatch {
                    index: 0,
                    expected: assignment_commitment.root,
                    got: prelude.commitments[0],
                },
            );
        }
        Ok(())
    }

    fn production_assignment_commitment_from_prelude<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        prelude: &TerminalProofPrelude,
    ) -> Result<TerminalOracleCommitment, NativeTerminalVerifyError> {
        if prelude.commitments.is_empty() {
            return Err(
                NativeTerminalVerifyError::TerminalPreludeCommitmentCountMismatch {
                    expected: 1,
                    got: 0,
                },
            );
        }
        let variables = 1
            + verifying_key.header.fingerprint.public_flat_len
            + verifying_key.header.fingerprint.witness_count as usize;
        Ok(TerminalOracleCommitment {
            label: Self::assignment_oracle_label().into(),
            values_len: variables,
            root: prelude.commitments[0],
        })
    }

    fn verify_terminal_oracle_commitment_identity(
        commitment: &TerminalOracleCommitment,
        expected_label: &str,
        expected_len: usize,
    ) -> Result<(), NativeTerminalVerifyError> {
        if commitment.label != expected_label {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLabelMismatch {
                    expected: expected_label.into(),
                    got: commitment.label.clone(),
                },
            );
        }
        if commitment.values_len != expected_len {
            return Err(
                NativeTerminalVerifyError::TerminalOracleCommitmentLengthMismatch {
                    label: expected_label.into(),
                    expected: expected_len,
                    got: commitment.values_len,
                },
            );
        }
        Ok(())
    }

    fn verify_terminal_witness_commitment_identity<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        commitment: &TerminalOracleCommitment,
    ) -> Result<(), NativeTerminalVerifyError> {
        Self::verify_terminal_oracle_commitment_identity(
            commitment,
            Self::witness_oracle_label(),
            verifying_key.header.fingerprint.witness_count as usize,
        )
    }

    fn verify_terminal_assignment_commitment_identity<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        commitment: &TerminalOracleCommitment,
    ) -> Result<(), NativeTerminalVerifyError> {
        let variables = 1
            + verifying_key.header.fingerprint.public_flat_len
            + verifying_key.header.fingerprint.witness_count as usize;
        Self::verify_terminal_oracle_commitment_identity(
            commitment,
            Self::assignment_oracle_label(),
            variables,
        )
    }

    fn verify_terminal_residual_commitment_identity<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        commitment: &TerminalOracleCommitment,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let relation = verifying_key.primitive_quadratic_relation()?;
        Self::verify_terminal_oracle_commitment_identity(
            commitment,
            Self::quadratic_residual_oracle_label(),
            relation.constraints.len(),
        )
    }

    fn verify_terminal_combined_validity_commitment_identity<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        commitment: &TerminalOracleCommitment,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let relation = verifying_key.primitive_quadratic_relation()?;
        let expected_len =
            relation.constraints.len() + Self::terminal_npo_validity_domain_len::<F>(verifying_key);
        Self::verify_terminal_oracle_commitment_identity(
            commitment,
            Self::combined_validity_oracle_label(),
            expected_len,
        )
    }

    fn verify_terminal_npo_exhaustive_residual_commitment_identity<F>(
        verifying_key: &NativeTerminalVerifyingKey<F>,
        commitment: &TerminalOracleCommitment,
    ) -> Result<(), NativeTerminalVerifyError>
    where
        F: Field + BasedVectorSpace<Goldilocks>,
    {
        let expected_len =
            Self::terminal_npo_polynomial_profile::<F>(verifying_key).residual_components;
        Self::verify_terminal_oracle_commitment_identity(
            commitment,
            Self::npo_exhaustive_residual_oracle_label(),
            expected_len,
        )
    }

