        assert!(matches!(
            NativeTerminalCompiler::decompress_terminal_fri_proof(&shortened_final_poly),
            Err(NativeTerminalVerifyError::TerminalNpoPolynomialColumnLengthMismatch { .. })
        ));

        let mut overlong_final_poly = proof.proof.clone();
        overlong_final_poly
