        let (_pk, unsigned_vk) = compiler.compile_primitive_terminal(&circuit).unwrap();
        let witness = execute_tip5_terminal_witness(&circuit, public_inputs.clone());

        let err = compiler
            .verify_assignment_with_goldilocks_npos(&unsigned_vk, &witness)
            .unwrap_err();
