        let (_pk, mut signed_vk) = compiler.compile_goldilocks_terminal(&circuit).unwrap();
        let digest = signed_vk
            .header
            .relation_digest
            .as_mut()
            .expect("digest must be present");
        digest.0[0] ^= 1;
        let err = compiler
            .verify_assignment_with_goldilocks_npos(&signed_vk, &witness)
            .unwrap_err();
