    fn witness_values<F: Copy>(witness: &TerminalWitness<F>) -> Vec<F> {
        (0..witness.traces.witness_trace.num_rows())
            .map(|idx| {
                *witness
                    .traces
                    .witness_trace
                    .get_value(WitnessId(idx as u32))
                    .expect("witness value must exist")
            })
            .collect()
    }

